<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;background:#0a0a0a;color:#e6e6e6;min-height:100vh}
.container{max-width:960px;margin:0 auto;padding:20px 16px}
h1{text-align:center;font-size:1.6rem;margin-bottom:4px;color:#fff}
.sub{text-align:center;color:#888;font-size:0.85rem;margin-bottom:16px}
.layout{display:grid;grid-template-columns:1fr 1fr;gap:14px}
@media(max-width:700px){.layout{grid-template-columns:1fr}}
.section{background:#161616;border:1px solid #222;border-radius:10px;padding:16px;margin-bottom:14px}
.section h3{font-size:0.9rem;color:#4da6ff;margin-bottom:10px}
.presets{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:12px}
.preset{padding:5px 12px;border-radius:6px;border:1px solid #333;background:#161616;color:#888;font-size:0.75rem;cursor:pointer;font-weight:600}
.preset:hover{border-color:#3b82f6;color:#4da6ff}
.preset.active{background:#1a2744;color:#4da6ff;border-color:#2a4a7a}
.field{margin-bottom:10px}
.field label{display:block;font-size:0.78rem;color:#888;margin-bottom:4px;font-weight:600}
.field input,.field select{width:100%;background:#0d0d0d;border:1px solid #333;border-radius:6px;padding:6px 10px;color:#e6e6e6;font-size:0.82rem}
.field-row{display:flex;gap:10px}
.field-row .field{flex:1}
.check-row{display:flex;align-items:center;gap:6px;margin-bottom:6px}
.check-row label{font-size:0.78rem;color:#aaa}
.kv-list{margin-bottom:8px}
.kv-row{display:flex;gap:6px;margin-bottom:4px}
.kv-row input{flex:1;background:#0d0d0d;border:1px solid #333;border-radius:4px;padding:4px 8px;color:#e6e6e6;font-size:0.78rem}
.kv-row button{padding:4px 8px;border-radius:4px;border:1px solid #333;background:#161616;color:#888;cursor:pointer;font-size:0.7rem}
.add-btn{padding:4px 10px;border-radius:4px;border:1px solid #333;background:#161616;color:#4da6ff;cursor:pointer;font-size:0.75rem;font-weight:600}
.output-area{width:100%;min-height:350px;max-height:600px;background:#0d0d0d;border:1px solid #333;border-radius:8px;padding:10px;color:#e6e6e6;font-family:'Fira Code',monospace;font-size:0.75rem;overflow:auto;white-space:pre}
.status-bar{display:flex;gap:8px;align-items:center;margin-bottom:10px;padding:8px 12px;background:#0d0d0d;border-radius:6px;font-size:0.78rem}
.status-code{padding:3px 8px;border-radius:4px;font-weight:700;font-family:'Fira Code',monospace}
.s2xx{background:#0d2818;color:#22c55e}
.s3xx{background:#1a1a06;color:#eab308}
.s4xx{background:#2d1b06;color:#f59e0b}
.s5xx{background:#2d0606;color:#ef4444}
.actions{display:flex;gap:8px;flex-wrap:wrap;margin-top:8px}
.btn{padding:6px 14px;border-radius:6px;border:1px solid #333;background:#161616;color:#ccc;font-size:0.8rem;cursor:pointer;font-weight:600}
.btn:hover{border-color:#3b82f6;color:#4da6ff}
.btn-primary{background:#1a2744;color:#4da6ff;border-color:#2a4a7a}
.toast{position:fixed;bottom:20px;right:20px;background:#238636;color:#fff;padding:10px 20px;border-radius:8px;font-size:0.85rem;display:none;z-index:99}
.footer{text-align:center;margin-top:24px;padding:16px 0;border-top:1px solid #222}
.footer a{color:#4da6ff;text-decoration:none;font-size:0.8rem}
.related{margin-top:20px;text-align:center;font-size:0.8rem;color:#666}
.related a{color:#4da6ff;text-decoration:none;margin:0 8px}
</style>
</head>
<body>
<div class="container">
<h1>API Mock Generator</h1>
<p class="sub">Generate realistic mock API responses for testing</p>

<div class="section">
<h3>Endpoint Presets</h3>
<div class="presets" id="presetList">
<div class="preset active" onclick="loadPreset('users')">Users List</div>
<div class="preset" onclick="loadPreset('user')">Single User</div>
<div class="preset" onclick="loadPreset('posts')">Blog Posts</div>
<div class="preset" onclick="loadPreset('products')">Products</div>
<div class="preset" onclick="loadPreset('auth')">Auth Token</div>
<div class="preset" onclick="loadPreset('error404')">404 Error</div>
<div class="preset" onclick="loadPreset('error500')">500 Error</div>
<div class="preset" onclick="loadPreset('paginated')">Paginated</div>
</div>
</div>

<div class="layout">
<div>
<div class="section">
<h3>Response Settings</h3>
<div class="field-row">
<div class="field"><label>Status Code</label><select id="statusCode" onchange="gen()">
<option value="200">200 OK</option>
<option value="201">201 Created</option>
<option value="204">204 No Content</option>
<option value="301">301 Moved</option>
<option value="400">400 Bad Request</option>
<option value="401">401 Unauthorized</option>
<option value="403">403 Forbidden</option>
<option value="404">404 Not Found</option>
<option value="422">422 Unprocessable</option>
<option value="429">429 Rate Limited</option>
<option value="500">500 Server Error</option>
<option value="503">503 Unavailable</option>
</select></div>
<div class="field"><label>Format</label><select id="format" onchange="gen()"><option value="json">JSON</option><option value="xml">XML</option></select></div>
</div>
<div class="field-row">
<div class="field"><label>Item Count</label><input id="count" type="number" value="5" min="1" max="50" onchange="gen()"></div>
<div class="field"><label>Delay (display only)</label><input id="delay" value="0ms" oninput="gen()"></div>
</div>
</div>

<div class="section">
<h3>Response Headers</h3>
<div class="kv-list" id="headersList"></div>
<button class="add-btn" onclick="addHeader()">+ Add Header</button>
</div>

<div class="section">
<h3>Data Shape</h3>
<div class="check-row"><input type="checkbox" id="wrapData" checked onchange="gen()"><label for="wrapData">Wrap in { data: [...] }</label></div>
<div class="check-row"><input type="checkbox" id="addMeta" onchange="gen()"><label for="addMeta">Add pagination meta</label></div>
<div class="check-row"><input type="checkbox" id="addTimestamp" checked onchange="gen()"><label for="addTimestamp">Add timestamps</label></div>
<div class="check-row"><input type="checkbox" id="addId" checked onchange="gen()"><label for="addId">Add IDs</label></div>
</div>
</div>

<div>
<div id="statusDisplay"></div>
<div class="output-area" id="output"></div>
<div class="actions">
<button class="btn btn-primary" onclick="copyOutput()">Copy</button>
<button class="btn" onclick="downloadOutput()">Download</button>
<button class="btn" onclick="regenerate()">Regenerate</button>
</div>
</div>
</div>

<div class="footer"><a href="https://gokuscraper.github.io/dev-vault/">Dev Vault

