<div class="container">
<h1>Diff Text</h1>
<p class="subtitle">Compare two texts. See additions, deletions, and changes highlighted.</p>

<div class="input-grid">
  <div class="input-panel">
    <div class="input-label">Original</div>
    <textarea id="textA" placeholder="Paste original text here...">The quick brown fox jumps over the lazy dog.
She sells sea shells by the sea shore.
Pack my box with five dozen liquor jugs.
How vexingly quick daft zebras jump.</textarea>
  </div>
  <div class="input-panel">
    <div class="input-label">Modified</div>
    <textarea id="textB" placeholder="Paste modified text here...">The quick brown cat jumps over the lazy dog.
She sells sea shells on the sea shore.
Pack my box with five dozen liquor jugs.
The five boxing wizards jump quickly.
How vexingly quick daft zebras leap.</textarea>
  </div>
</div>

<div class="toolbar">
  <button class="btn primary" onclick="compare()">Compare</button>
  <button class="btn" onclick="swap()">Swap</button>
  <button class="btn" onclick="clearAll()">Clear</button>
  <label class="toggle-label"><input type="checkbox" id="ignoreWs" onchange="compare()"> Ignore whitespace</label>
  <label class="toggle-label"><input type="checkbox" id="ignoreCase" onchange="compare()"> Ignore case</label>
</div>

<div class="mode-toggle">
  <button class="mode-btn active" onclick="setMode('unified')" id="modeUnified">Unified</button>
  <button class="mode-btn" onclick="setMode('inline')" id="modeInline">Word Diff</button>
</div>

<div class="stats-bar" id="statsBar"></div>
<div class="diff-output" id="diffOutput"></div>
</div>

<footer>
  <a href="https://github.com/gokuscraper/diff-text">GitHub</a> ·
  Also: <a href="https://gokuscraper.github.io/dev-vault/word-count/">Word Count</a> ·
  <a href="https://gokuscraper.github.io/dev-vault/json-format/">JSON Format</a> ·
  <a href="https://gokuscraper.github.io/dev-vault/regex-test/">Regex Test</a>
</footer>

<script>
const $=id=>document.getElementById(id);
let mode='unified';

function setMode(m){
  mode=m;
  document.querySelectorAll('.mode-btn').forEach(b=>b.classList.remove('active'));
  $(m==='unified'?'modeUnified':'modeInline').classList.add('active');
  compare();
}

function swap(){
  const a=$('textA').value;
  $('textA').value=$('textB').value;
  $('textB').value=a;
  compare();
}

function clearAll(){
  $('textA').value='';
  $('textB').value='';
  $('diffOutput').innerHTML='';
  $('statsBar').innerHTML='';
}

// Simple LCS-based line diff (uses normalize() for comparison, keeps original text)
function diffLines(a,b){
  const na=a.map(normalize),nb=b.map(normalize);
  const m=a.length,n=b.length;
  const dp=Array(m+1).fill(null).map(()=>Array(n+1).fill(0));
  for(let i=1;i<=m;i++){
    for(let j=1;j<=n;j++){
      dp[i][j]=na[i-1]===nb[j-1]?dp[i-1][j-1]+1:Math.max(dp[i-1][j],dp[i][j-1]);
    }
  }
  const result=[];
  let i=m,j=n;
  while(i>0||j>0){
    if(i>0&&j>0&&na[i-1]===nb[j-1]){
      result.unshift({type:'same',lineA:i,lineB:j,text:a[i-1]});
      i--;j--;
    }else if(j>0&&(i===0||dp[i][j-1]>=dp[i-1][j])){
      result.unshift({type:'add',lineB:j,text:b[j-1]});
      j--;
    }else{
      result.unshift({type:'del',lineA:i,text:a[i-1]});
      i--;
    }
  }
  return result;
}

// Word-level diff for changed lines
function diffWords(a,b){
  const wa=a.split(/(\s+)/),wb=b.split(/(\s+)/);
  const m=wa.length,n=wb.length;
  const dp=Array(m+1).fill(null).map(()=>Array(n+1).fill(0));
  for(let i=1;i<=m;i++)for(let j=1;j<=n;j++)
    dp[i][j]=wa[i-1]===wb[j-1]?dp[i-1][j-1]+1:Math.max(dp[i-1][j],dp[i][j-1]);
  const result=[];
  let i=m,j=n;
  while(i>0||j>0){
    if(i>0&&j>0&&wa[i-1]===wb[j-1]){result.unshift({type:'same',text:wa[i-1]});i--;j--}
    else if(j>0&&(i===0||dp[i][j-1]>=dp[i-1][j])){result.unshift({type:'add',text:wb[j-1]});j--}
    else{result.unshift({type:'del',text:wa[i-1]});i--}
  }
  return result;
}

function esc(s){return s.replace(/&/g,'&').replace(/</g,'<').replace(/>/g,'>')}

function normalize(line){
  let s=line;
  if($('ignoreCase').checked)s=s.toLowerCase();
  if($('ignoreWs').checked)s=s.replace(/\s+/g,' ').trim();
  return s;
}

function compare(){
  const a=$('textA').value.split('\n');
  const b=$('textB').value.split('\n');
  const diff=diffLines(a,b);

  let adds=0,dels=0,same=0;
  diff.forEach(d=>{if(d.type==='add')adds++;else if(d.type==='del')dels++;else same++});

  $('statsBar').innerHTML=`
    <div class="stat add"><span class="n">+${adds}</span> added</div>
    <div class="stat del"><span class="n">-${dels}</span> removed</div>
    <div class="stat same"><span class="n">${same}</span> unchanged</div>
  `;

  if(mode==='inline'){
    renderWordDiff(diff);
  }else{
    renderUnified(diff);
  }
}

function renderUnified(diff){
  let html='';
  diff.forEach(d=>{
    const cls=d.type==='add'?'diff-add':d.type==='del'?'diff-del':'diff-same';
    const marker=d.type==='add'?'+':d.type==='del'?'-':' ';
    const numA=d.lineA||'';
    const numB=d.lineB||'';
    html+=`<div class="diff-line ${cls}">
      <div class="diff-num">${numA}</div>
      <div class="diff-num">${numB}</div>
      <div class="diff-marker">${marker}</div>
      <div class="diff-content">${esc(d.text)}</div>
    </div>`;
  });
  $('diffOutput').innerHTML=html;
}

function renderWordDiff(diff){
  // Pair up consecutive del+add as changes for word-level diff
  let html='';
  let i=0;
  while(i<diff.length){
    if(diff[i].type==='del'&&i+1<diff.length&&diff[i+1].type==='add'){
      // Changed line — show word diff
      const wd=diffWords(diff[i].text,diff[i+1].text);
      let content='';
      wd.forEach(w=>{
        if(w.type==='same')content+=esc(w.text);
        else if(w.type==='add')content+=`<span class="word-add">${esc(w.text)}</span>`;
        else content+=`<span class="word-del">${esc(w.text)}</span>`;
      });
      html+=`<div class="diff-line diff-chg">
        <div class="diff-num">${diff[i].lineA||''}</div>
        <div class="diff-num">${diff[i+1].lineB||''}</div>
        <div class="diff-marker">~</div>
        <div class="diff-content">${content}</div>
      </div>`;
      i+=2;
    }else{
      const d=diff[i];
      const cls=d.type==='add'?'diff-add':d.type==='del'?'diff-del':'diff-same';
      const marker=d.type==='add'?'+':d.type==='del'?'-':' ';
      html+=`<div class="diff-line ${cls}">
        <div class="diff-num">${d.lineA||''}</div>
        <div class="diff-num">${d.lineB||''}</div>
        <div class="diff-marker">${marker}</div>
        <div class="diff-content">${esc(d.text)}</div>
      </div>`;
      i++;
    }
  }
  $('diffOutput').innerHTML=html;
}

// Init
compare();
</script>
