    .h-key  { font-weight: 600; font-family: 'SFMono-Regular', Consolas, monospace; color: var(--text); min-width: 60px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 90px; }
    .h-code { color: var(--accent); font-family: 'SFMono-Regular', Consolas, monospace; flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
    .h-num  { color: var(--yellow); font-family: 'SFMono-Regular', Consolas, monospace; white-space: nowrap; }
    .h-mods { color: var(--text2); font-size: 11px; white-space: nowrap; }

    .clear-btn {
      background: none;
      border: 1px solid var(--border);
      border-radius: 6px;
      color: var(--text2);
      font-size: 12px;
      padding: 3px 10px;
