<body>

<header>
  <h1>JavaScript Keycode Finder</h1>
  <span class="badge">keydown · keyup · keypress</span>
  <span class="sub">Press any key to inspect all event properties</span>
</header>

<div class="layout">
  <!-- ── Left column ─────────────────────────────────────────── -->
  <div>

    <!-- Press area -->
    <div class="press-area" id="pressArea" tabindex="0">
      <div id="pressHint" class="press-hint">Press any key...</div>
      <div id="keyDisplay"       style="display:none"></div>
      <div id="keyCodeDisplay"   style="display:none"></div>
