      </tr>
      <tr>
        <td>event.which <span class="deprecated">deprecated</span></td>
        <td><div class="prop-value"><span class="val" id="p-which">—</span><button class="copy-btn" data-prop="p-which">copy</button></div></td>
      </tr>
      <tr>
        <td>event.charCode <span class="deprecated">deprecated</span></td>
