  </div><!-- /right -->

</div><!-- /layout -->

<div class="toast" id="toast"></div>

<script>
// ── Data ────────────────────────────────────────────────────────────────────
const LOCATION_MAP = { 0:'Standard', 1:'Left', 2:'Right', 3:'Numpad' };

const QUICK_REF = [
  {n:'Backspace', c:8},  {n:'Tab',       c:9},
  {n:'Enter',    c:13},  {n:'Shift',     c:16},
  {n:'Ctrl',     c:17},  {n:'Alt',       c:18},
  {n:'CapsLock', c:20},  {n:'Escape',    c:27},
  {n:'Space',    c:32},  {n:'PageUp',    c:33},
  {n:'PageDown', c:34},  {n:'End',       c:35},
  {n:'Home',     c:36},  {n:'← Arrow',   c:37},
  {n:'↑ Arrow',  c:38},  {n:'→ Arrow',   c:39},
  {n:'↓ Arrow',  c:40},  {n:'Delete',    c:46},
  {n:'0 – 9',    c:'48–57', noopy:true},
  {n:'A – Z',    c:'65–90', noopy:true},
  {n:'F1',       c:112}, {n:'F2',        c:113},
  {n:'F3',       c:114}, {n:'F4',        c:115},
  {n:'F5',       c:116}, {n:'F6',        c:117},
  {n:'F7',       c:118}, {n:'F8',        c:119},
  {n:'F9',       c:120}, {n:'F10',       c:121},
  {n:'F11',      c:122}, {n:'F12',       c:123},
  {n:'Num Lock', c:144}, {n:'Scroll Lk', c:145},
  {n:'; colon',  c:186}, {n:'= plus',    c:187},
  {n:', comma',  c:188}, {n:'- minus',   c:189},
  {n:'. period', c:190}, {n:'/ slash',   c:191},
];

// ── State ────────────────────────────────────────────────────────────────────
const keyHistory = [];
const MAX_HIST = 20;
let lastEvt = null;

// ── DOM refs ─────────────────────────────────────────────────────────────────
const pressArea    = document.getElementById('pressArea');
const pressHint    = document.getElementById('pressHint');
const keyDisplay   = document.getElementById('keyDisplay');
const keyCodeDisp  = document.getElementById('keyCodeDisplay');
const keyNumDisp   = document.getElementById('keyNumberDisplay');
const historyList  = document.getElementById('historyList');
const histCount    = document.getElementById('histCount');
const snippetPre   = document.getElementById('snippetPre');
const toastEl      = document.getElementById('toast');
const tabDown      = document.getElementById('tab-keydown');
const tabPress     = document.getElementById('tab-keypress');
const tabUp        = document.getElementById('tab-keyup');

// ── Tab flash ────────────────────────────────────────────────────────────────
const tabTimers = {};
function flashTab(el, cls) {
  el.classList.add(cls);
  clearTimeout(tabTimers[cls]);
  tabTimers[cls] = setTimeout(() => el.classList.remove(cls), 500);
}

// ── Key event handling ───────────────────────────────────────────────────────
document.addEventListener('keydown', e => {
  if (e.key === 'Tab') e.preventDefault(); // keep focus, show Tab key
  flashTab(tabDown,  'fired-down');
  lastEvt = e;
  updateDisplay(e);
  updateSnippet(e);
  addHistory(e);
});

document.addEventListener('keypress', () => flashTab(tabPress, 'fired-press'));
document.addEventListener('keyup',    () => flashTab(tabUp,    'fired-up'));

pressArea.addEventListener('click', () => pressArea.focus());

// ── Update main display ───────────────────────────────────────────────────────
function updateDisplay(e) {
  const label = e.key === ' ' ? 'Space' : e.key;

  pressHint.style.display   = 'none';
  keyDisplay.style.display  = 'block';
  keyCodeDisp.style.display = 'block';
  keyNumDisp.style.display  = 'block';

  keyDisplay.textContent  = label;
  keyCodeDisp.textContent = e.code;
  keyNumDisp.textContent  = e.keyCode;

  // Responsive font size for long key names
  const len = label.length;
  keyDisplay.style.fontSize = len > 10 ? '24px' : len > 6 ? '36px' : len > 3 ? '48px' : '60px';

  pressArea.classList.add('active');

  // Property table
  set('p-key',      e.key);
  set('p-code',     e.code);
  set('p-keyCode',  e.keyCode);
  set('p-which',    e.which);
  set('p-charCode', 0); // charCode is always 0 on keydown; keypress fires for char keys
  set('p-location', `${e.location} — ${LOCATION_MAP[e.location] ?? e.location}`);
  set('p-repeat',   String(e.repeat));

  // Modifiers
  setMod('mod-ctrl',  e.ctrlKey);
  setMod('mod-shift', e.shiftKey);
  setMod('mod-alt',   e.altKey);
  setMod('mod-meta',  e.metaKey);
}

function set(id, v)    { document.getElementById(id).textContent = v; }
function setMod(id, v) { document.getElementById(id).classList.toggle('active', v); }

// ── Code snippet ──────────────────────────────────────────────────────────────
function esc(s) { return s.replace(/&/g,'&').replace(/</g,'<').replace(/>/g,'>'); }
function escQ(s){ return s.replace(/'/g, "\\'"); }

function updateSnippet(e) {
  const k  = esc(escQ(e.key));
  const co = esc(e.code);
  const kc = e.keyCode;

  snippetPre.innerHTML =
`<span class="cm">// Modern — match by character (layout-aware)</span>
<span class="kw">document</span>.<span class="fn">addEventListener</span>(<span class="str">'keydown'</span>, (e) => {
  <span class="kw">if</span> (e.key === <span class="str">'${k}'</span>) {
    console.<span class="fn">log</span>(<span class="str">'${k} pressed'</span>);
  }
});

<span class="cm">// Modern — match by physical key (layout-independent)</span>
<span class="kw">document</span>.<span class="fn">addEventListener</span>(<span class="str">'keydown'</span>, (e) => {
  <span class="kw">if</span> (e.code === <span class="str">'${co}'</span>) { <span class="cm">/* ... */</span> }
});

<span class="cm">// Legacy — avoid in new code</span>
<span class="cm">// e.keyCode === <span class="nm">${kc}</span>  |  e.which === <span class="nm">${kc}</span></span>`;
}

// ── History ───────────────────────────────────────────────────────────────────
function addHistory(e) {
  keyHistory.unshift({
    key: e.key, code: e.code, keyCode: e.keyCode,
    ctrl: e.ctrlKey, shift: e.shiftKey, alt: e.altKey, meta: e.metaKey,
  });
  if (keyHistory.length > MAX_HIST) keyHistory.pop();
  renderHistory();
}

function renderHistory() {
  histCount.textContent = `(${keyHistory.length})`;
  if (!keyHistory.length) {
    historyList.innerHTML = '<div style="color:var(--text2);font-size:12px;padding:8px;text-align:center">No keys pressed yet</div>';
    return;
  }
  historyList.innerHTML = keyHistory.map(h => {
    const label = h.key === ' ' ? 'Space' : h.key;
    const mods  = [h.ctrl&&'Ctrl', h.shift&&'Shift', h.alt&&'Alt', h.meta&&'Meta'].filter(Boolean).join('+');
    return `<div class="history-item" data-copy="${esc(h.key)}">
      <span class="h-key">${esc(label)}</span>
      <span class="h-code">${esc(h.code)}</span>
      <span class="h-num">${h.keyCode}</span>
      ${mods ? `<span class="h-mods">${esc(mods)}</span>` : ''}
    </div>`;
  }).join('');

  // attach click handlers
  historyList.querySelectorAll('.history-item').forEach(el => {
    el.addEventListener('click', () => {
      const v = el.dataset.copy;
      copyText(v);
      showToast(`Copied: ${v === ' ' ? 'Space' : v}`);
    });
  });
}

document.getElementById('clearHistBtn').addEventListener('click', () => {
  keyHistory.length = 0;
  renderHistory();
});

// ── Copy handlers (event delegation for copy buttons) ────────────────────────
document.querySelector('.props-table').addEventListener('click', e => {
  const btn = e.target.closest('.copy-btn[data-prop]');
  if (!btn) return;
  const val = document.getElementById(btn.dataset.prop).textContent;
  if (val === '—') return;
  copyText(val);
  btn.textContent = 'done';
  btn.classList.add('copied');
  setTimeout(() => { btn.textContent = 'copy'; btn.classList.remove('copied'); }, 1200);
  showToast(`Copied: ${val}`);
});

document.getElementById('copySnippetBtn').addEventListener('click', () => {
  if (!lastEvt) return;
  copyText(snippetPre.innerText || snippetPre.textContent);
  showToast('Snippet copied!');
});

// ── Quick reference ───────────────────────────────────────────────────────────
const refGrid = document.getElementById('refGrid');
QUICK_REF.forEach(item => {
  const el = document.createElement('div');
  el.className = 'ref-item';
  el.innerHTML = `<span class="r-name">${esc(item.n)}</span><span class="r-code">${item.c}</span>`;
  if (!item.noopy && typeof item.c === 'number') {
    el.title = 'Click to copy keyCode';
    el.addEventListener('click', () => {
      copyText(String(item.c));
      showToast(`Copied: ${item.c}`);
    });
  }
  refGrid.appendChild(el);
});

// ── Clipboard ────────────────────────────────────────────────────────────────
function copyText(text) {
  if (navigator.clipboard) {
    navigator.clipboard.writeText(text).catch(() => fallback(text));
  } else { fallback(text); }
}
function fallback(text) {
  const ta = Object.assign(document.createElement('textarea'), {
    value: text, style: 'position:fixed;opacity:0'
  });
  document.body.appendChild(ta);
  ta.select();
  document.execCommand('copy');
  ta.remove();
}

// ── Toast ────────────────────────────────────────────────────────────────────
let toastTimer;
function showToast(msg) {
  toastEl.textContent = msg;
  toastEl.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => toastEl.classList.remove('show'), 1600);
}
</script>
