.ref-table{width:100%;border-collapse:collapse;font-size:.8125rem}
.ref-table th,.ref-table td{text-align:left;padding:6px 16px;border-bottom:1px solid var(--border)}
.ref-table tr:last-child td{border-bottom:none}
.ref-table th{color:var(--text2);font-weight:600;background:var(--bg);font-size:.75rem;text-transform:uppercase;letter-spacing:.04em}
.ref-table td:first-child{font-family:monospace;color:var(--accent);white-space:nowrap}

footer{text-align:center;padding:16px;font-size:.8125rem;color:var(--text2);border-top:1px solid var(--border)}
</style>
</head>
<body>

<div class="container">
  <h1>Regex Replace</h1>
  <p class="subtitle">Find & replace with regular expressions — live diff preview, backreferences, 10 presets.</p>

  <!-- Source text -->
  <div class="section">
    <label for="source">Source Text</label>
    <div class="highlight-wrap">
      <div class="highlight-backdrop" id="inputBackdrop"></div>
      <textarea id="source" placeholder="Paste your text here…" spellcheck="false"></textarea>
    </div>
  </div>

  <!-- Pattern + Replacement -->
  <div class="pattern-row">
    <div>
      <label for="pattern">Pattern</label>
      <input type="text" id="pattern" placeholder="e.g. (\w+)@(\w+)\.(\w+)" spellcheck="false" autocomplete="off">
    </div>
    <div>
      <label for="replacement">Replacement</label>
      <input type="text" id="replacement" placeholder="e.g. $1 [at] $2.$3" spellcheck="false" autocomplete="off">
    </div>
  </div>

  <!-- Flags -->
  <div class="flags-row">
    <label>Flags</label>
    <button class="flag-btn active" data-flag="g" title="Global — replace all occurrences">g</button>
    <button class="flag-btn" data-flag="i" title="Case-insensitive">i</button>
    <button class="flag-btn" data-flag="m" title="Multiline — ^ and $ match line boundaries">m</button>
    <button class="flag-btn" data-flag="s" title="DotAll — . also matches newlines">s</button>
    <button class="flag-btn" data-flag="u" title="Unicode — enable full Unicode matching">u</button>
  </div>

  <!-- Stats + error -->
  <div class="stats-bar" id="statsBar">
    <div class="match-count" id="matchCount"></div>
  </div>

  <!-- Diff legend -->
  <div class="diff-legend">
    <span><span class="swatch match"></span>Match (input)</span>
    <span><span class="swatch del"></span>Removed</span>
    <span><span class="swatch ins"></span>Inserted</span>
  </div>

  <!-- Result with diff backdrop -->
  <div class="section">
    <label for="output">Result</label>
    <div class="highlight-wrap">
      <div class="highlight-backdrop diff-backdrop" id="outputBackdrop"></div>
      <textarea id="output" readonly placeholder="Result appears here…" spellcheck="false"></textarea>
    </div>
  </div>

  <!-- Actions -->
  <div class="btn-row">
    <button class="btn" id="copyBtn">Copy Result</button>
    <button class="btn-ghost" id="clearBtn">Clear All</button>
  </div>

  <!-- Presets -->
  <div class="presets">
    <h2>Presets</h2>
    <div class="preset-grid" id="presetGrid"></div>
  </div>

  <!-- Regex syntax reference (collapsible) -->
  <div class="ref-panel">
    <button class="ref-toggle" id="regexToggle">
      Regex Syntax Quick Reference
      <span class="chevron">▼</span>
    </button>
    <div class="ref-body" id="regexBody">
      <table class="ref-table">
        <thead><tr><th>Pattern</th><th>Description</th></tr></thead>
        <tbody>
          <tr><td>.</td><td>Any character except newline (use s flag to include newlines)</td></tr>
          <tr><td>\d / \D</td><td>Digit / Non-digit [0-9]</td></tr>
          <tr><td>\w / \W</td><td>Word character / Non-word [a-zA-Z0-9_]</td></tr>
          <tr><td>\s / \S</td><td>Whitespace / Non-whitespace</td></tr>
          <tr><td>^ / $</td><td>Start / End of string (or line with m flag)</td></tr>
          <tr><td>\b / \B</td><td>Word boundary / Non-word boundary</td></tr>
          <tr><td>[abc]</td><td>Character class — matches a, b, or c</td></tr>
          <tr><td>[^abc]</td><td>Negated class — anything except a, b, c</td></tr>
          <tr><td>[a-z]</td><td>Range — any lowercase letter</td></tr>
          <tr><td>a|b</td><td>Alternation — matches a or b</td></tr>
          <tr><td>*</td><td>Zero or more (greedy)</td></tr>
          <tr><td>+</td><td>One or more (greedy)</td></tr>
          <tr><td>?</td><td>Zero or one (makes quantifier lazy when appended)</td></tr>
          <tr><td>{n} / {n,m}</td><td>Exactly n / Between n and m repetitions</td></tr>
          <tr><td>(abc)</td><td>Capturing group</td></tr>
          <tr><td>(?:abc)</td><td>Non-capturing group</td></tr>
          <tr><td>(?<name>abc)</td><td>Named capturing group</td></tr>
          <tr><td>(?=abc) / (?!abc)</td><td>Positive / Negative lookahead</td></tr>
          <tr><td>(?<=abc) / (?<!abc)</td><td>Positive / Negative lookbehind</td></tr>
        </tbody>
      </table>
    </div>
  </div>

  <!-- Replacement syntax reference (collapsible) -->
  <div class="ref-panel">
    <button class="ref-toggle" id="replToggle">
      Replacement Syntax Quick Reference
      <span class="chevron">▼</span>
    </button>
    <div class="ref-body" id="replBody">
      <table class="ref-table">
        <thead><tr><th>Token</th><th>Description</th></tr></thead>
        <tbody>
          <tr><td>$1, $2, …</td><td>Captured group by number</td></tr>
          <tr><td>$<name></td><td>Named capture group</td></tr>
          <tr><td>$&</td><td>Entire matched substring</td></tr>
          <tr><td>$`</td><td>Text before the match</td></tr>
          <tr><td>$'</td><td>Text after the match</td></tr>
          <tr><td>$$</td><td>Literal dollar sign $</td></tr>
        </tbody>
      </table>
    </div>
  </div>

</div>

<footer>
</footer>

<script>
// ── DOM refs ──
const sourceEl      = document.getElementById('source');
const patternEl     = document.getElementById('pattern');
const replacementEl = document.getElementById('replacement');
const outputEl      = document.getElementById('output');
const matchCountEl  = document.getElementById('matchCount');
const statsBar      = document.getElementById('statsBar');
const inputBackdrop = document.getElementById('inputBackdrop');
const outputBackdrop= document.getElementById('outputBackdrop');
const copyBtn       = document.getElementById('copyBtn');
const clearBtn      = document.getElementById('clearBtn');

// ── Flag state ──
const flags = { g: true, i: false, m: false, s: false, u: false };

// ── Presets (10) ──
const PRESETS = [
  {
    name: 'Remove HTML tags',
    pattern: '<[^>]+>',
    replacement: '',
    flags: 'g',
  },
  {
    name: 'Extract emails',
    pattern: '[\\w.+\\-]+@[\\w\\-]+\\.[\\w.]+',
    replacement: '$&\n',
    flags: 'g',
  },
  {
    name: 'camelCase → snake_case',
    pattern: '([a-z])([A-Z])',
    replacement: '$1_$2',
    flags: 'g',
  },
  {
    name: 'Remove blank lines',
    pattern: '^[ \\t]*\\n',
    replacement: '',
    flags: 'gm',
  },
  {
    name: 'Normalize whitespace',
    pattern: '[ \\t]+',
    replacement: ' ',
    flags: 'g',
  },
  {
    name: 'Wrap words in <b>',
    pattern: '(\\b\\w+\\b)',
    replacement: '<b>$1</b>',
    flags: 'g',
  },
  {
    name: 'Swap first/last name',
    pattern: '^([A-Z][a-z]+) ([A-Z][a-z]+)$',
    replacement: '$2, $1',
    flags: 'gm',
  },
  {
    name: 'Format phone numbers',
    pattern: '(\\d{3})[\\s.\\-]?(\\d{3})[\\s.\\-]?(\\d{4})',
    replacement: '($1) $2-$3',
    flags: 'g',
  },
  {
    name: 'Remove // comments',
    pattern: '[ \\t]*\\/\\/[^\\n]*',
    replacement: '',
    flags: 'g',
  },
  {
    name: 'Tabs → 4 spaces',
    pattern: '\\t',
    replacement: '    ',
    flags: 'g',
  },
];

// ── Render presets ──
const presetGrid = document.getElementById('presetGrid');
PRESETS.forEach(p => {
  const btn = document.createElement('button');
  btn.className = 'preset-btn';
  btn.title = `Pattern: ${p.pattern}\nReplacement: ${p.replacement || '(empty)'}\nFlags: ${p.flags}`;
  btn.innerHTML =
    `<div class="preset-name">${esc(p.name)}</div>` +
    `<div class="preset-detail">${esc(p.pattern)} → ${esc(p.replacement || '(empty)')}</div>`;
  btn.addEventListener('click', () => applyPreset(p));
  presetGrid.appendChild(btn);
});

function applyPreset(p) {
  patternEl.value     = p.pattern;
  replacementEl.value = p.replacement;
  for (const f in flags) flags[f] = false;
  for (const c of (p.flags || '')) if (c in flags) flags[c] = true;
  syncFlagButtons();
  update();
}

// ── Flag buttons ──
document.querySelectorAll('.flag-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    const f = btn.dataset.flag;
    flags[f] = !flags[f];
    btn.classList.toggle('active', flags[f]);
    update();
  });
});

function syncFlagButtons() {
  document.querySelectorAll('.flag-btn').forEach(btn => {
    btn.classList.toggle('active', flags[btn.dataset.flag]);
  });
}

function getFlags() {
  return Object.entries(flags).filter(([, v]) => v).map(([k]) => k).join('');
}

// ── Collapsible panels ──
function setupToggle(toggleId, bodyId) {
  const toggle = document.getElementById(toggleId);
  const body   = document.getElementById(bodyId);
  toggle.addEventListener('click', () => {
    const open = body.classList.toggle('open');
    toggle.classList.toggle('open', open);
  });
}
setupToggle('regexToggle', 'regexBody');
setupToggle('replToggle',  'replBody');

// ── Utilities ──
function esc(s) {
  return s
    .replace(/&/g, '&')
    .replace(/</g, '<')
    .replace(/>/g, '>')
    .replace(/"/g, '"');
}

// Escape for backdrop overlay (preserves HTML tags we inject)
function escText(s) {
  return s
    .replace(/&/g, '&')
    .replace(/</g, '<')
    .replace(/>/g, '>');
}

// ── Core update ──
function update() {
  const source  = sourceEl.value;
  const patStr  = patternEl.value;
  const repl    = replacementEl.value;

  // Remove old error
  const oldErr = statsBar.querySelector('.error-pill');
  if (oldErr) oldErr.remove();

  if (!patStr) {
    outputEl.value         = source;
    matchCountEl.innerHTML = '';
    inputBackdrop.innerHTML  = escText(source);
    outputBackdrop.innerHTML = escText(source);
    return;
  }

  // Build regex
  let regex;
  try {
    regex = new RegExp(patStr, getFlags().replace('g','') + 'g'); // always global for iteration
  } catch (e) {
    matchCountEl.innerHTML = '';
    const pill = document.createElement('div');
    pill.className = 'error-pill';
    pill.textContent = e.message;
    statsBar.appendChild(pill);
    outputEl.value           = source;
    inputBackdrop.innerHTML  = escText(source);
    outputBackdrop.innerHTML = escText(source);
    return;
  }

  // ── Collect all matches ──
  const allMatches = [];
  let m;
  let safety = 0;
  regex.lastIndex = 0;
  while ((m = regex.exec(source)) !== null && safety < 200000) {
    safety++;
    allMatches.push({ index: m.index, end: m.index + m[0].length, match: m });
    if (m[0].length === 0) regex.lastIndex++;
    if (!flags.g && allMatches.length >= 1) break;
  }

  // Match count
  matchCountEl.innerHTML =
    `<span class="n">${allMatches.length}</span> match${allMatches.length !== 1 ? 'es' : ''} found`;

  // ── Build input backdrop (yellow marks on source) ──
  {
    let html = '';
    let last = 0;
    for (const hit of allMatches) {
      html += escText(source.slice(last, hit.index));
      html += '<mark>' + escText(hit.match[0]) + '</mark>';
      last = hit.end;
    }
    html += escText(source.slice(last));
    inputBackdrop.innerHTML = html;
  }

  // ── Build output with diff (red=deleted, green=inserted) ──
  {
    // We need a single-match regex for String.replace
    const replFlags = getFlags().replace('g', ''); // without g for per-hit replace
    const singleRe  = new RegExp(patStr, replFlags);

    let outputText = '';
    let outHtml    = '';
    let last = 0;

    for (const hit of allMatches) {
      // Text before this match — unchanged
      const before = source.slice(last, hit.index);
      outputText += before;
      outHtml    += escText(before);

      // Compute replacement for this specific match
      const replaced = hit.match[0].replace(singleRe, repl);

      outputText += replaced;

      // Show diff: deleted (original) then inserted (replacement)
      if (replaced !== hit.match[0]) {
        outHtml += '<mark class="del">' + escText(hit.match[0]) + '</mark>';
        if (replaced.length > 0) {
          outHtml += '<mark class="ins">' + escText(replaced) + '</mark>';
        }
      } else {
        // No change — just unchanged text
        outHtml += escText(replaced);
      }

      last = hit.end;
    }

    const tail = source.slice(last);
    outputText += tail;
    outHtml    += escText(tail);

    outputEl.value           = outputText;
    outputBackdrop.innerHTML = outHtml;
  }

  syncScroll(sourceEl,  inputBackdrop);
  syncScroll(outputEl, outputBackdrop);
}

// ── Scroll sync ──
function syncScroll(textarea, backdrop) {
  backdrop.scrollTop  = textarea.scrollTop;
  backdrop.scrollLeft = textarea.scrollLeft;
}

sourceEl.addEventListener('scroll',     () => syncScroll(sourceEl,  inputBackdrop));
outputEl.addEventListener('scroll',     () => syncScroll(outputEl, outputBackdrop));

// ── Input listeners ──
sourceEl.addEventListener('input',      update);
patternEl.addEventListener('input',     update);
replacementEl.addEventListener('input', update);

// ── Copy ──
copyBtn.addEventListener('click', () => {
  navigator.clipboard.writeText(outputEl.value).then(() => {
    copyBtn.textContent = 'Copied!';
    setTimeout(() => { copyBtn.textContent = 'Copy Result'; }, 1500);
  }).catch(() => {
    // Fallback for non-https
    outputEl.select();
    document.execCommand('copy');
    copyBtn.textContent = 'Copied!';
    setTimeout(() => { copyBtn.textContent = 'Copy Result'; }, 1500);
  });
});

// ── Clear ──
clearBtn.addEventListener('click', () => {
  sourceEl.value      = '';
  patternEl.value     = '';
  replacementEl.value = '';
  for (const f in flags) flags[f] = false;
  flags.g = true;
  syncFlagButtons();
  update();
});

// ── Init ──
update();
</script>
