<body>
<div class="container">
<h1>Regex Test</h1>
<p class="subtitle">Live regular expression tester. Type and see matches instantly.</p>

<div class="regex-row">
  <div class="regex-slash">/</div>
  <input type="text" id="regexInput" value="(\w+)@(\w+)\.(\w+)" placeholder="pattern" autocomplete="off">
  <div class="regex-slash">/</div>
  <input type="text" id="flagsInput" value="g" placeholder="gi" autocomplete="off">
</div>

<div class="flag-toggles">
  <button class="flag-btn active" data-flag="g" onclick="toggleFlag('g')">g global</button>
  <button class="flag-btn" data-flag="i" onclick="toggleFlag('i')">i ignore case</button>
  <button class="flag-btn" data-flag="m" onclick="toggleFlag('m')">m multiline</button>
  <button class="flag-btn" data-flag="s" onclick="toggleFlag('s')">s dotAll</button>
  <button class="flag-btn" data-flag="u" onclick="toggleFlag('u')">u unicode</button>
</div>

<div id="error"></div>

<div class="test-area">
  <textarea id="testInput" placeholder="Enter test string here...">Hello user@example.com and admin@test.org
Contact support@company.net for help
Invalid: not-an-email, @missing, no@dots</textarea>
</div>

<div class="match-info" id="matchInfo"></div>

<div class="cheatsheet">
  <h2>Common Patterns</h2>
  <div class="patterns" id="patterns"></div>
</div>
</div>

