const $=id=>document.getElementById(id);
const API='https://dev.to/api';

$('username').addEventListener('keydown',e=>{if(e.key==='Enter')analyze()});

async function analyze(){
  const user=$('username').value.trim();
  if(!user)return;
  $('analyze').disabled=true;
  $('analyze').textContent='Loading...';
  $('error').style.display='none';
  $('results').style.display='none';

  try{
    const articles=await fetchAllArticles(user);
    if(!articles.length)throw new Error('No published articles found for @'+user);
    render(user,articles);
    $('results').style.display='block';
  }catch(e){
    $('error').textContent=e.message;
    $('error').style.display='block';
  }finally{
    $('analyze').disabled=false;
    $('analyze').textContent='Analyze';
  }
}

async function fetchAllArticles(user){
  let all=[],page=1;
  while(true){
    const r=await fetch(`${API}/articles?username=${encodeURIComponent(user)}&per_page=100&page=${page}`);
    if(!r.ok)throw new Error('User not found or API error ('+r.status+')');
    const data=await r.json();
    if(!data.length)break;
    all=all.concat(data);
    if(data.length<100)break;
    page++;
  }
  return all;
}

function render(user,articles){
  const totalReactions=articles.reduce((s,a)=>s+a.positive_reactions_count,0);
  const totalComments=articles.reduce((s,a)=>s+a.comments_count,0);
  const avgReactions=articles.length?(totalReactions/articles.length).toFixed(1):0;
  const avgComments=articles.length?(totalComments/articles.length).toFixed(1):0;

  // Date range
  const dates=articles.map(a=>new Date(a.published_at)).sort((a,b)=>a-b);
  const firstDate=dates[0];
  const lastDate=dates[dates.length-1];
  const daySpan=Math.max(1,Math.ceil((lastDate-firstDate)/(1000*60*60*24)));
  const articlesPerWeek=(articles.length/(daySpan/7)).toFixed(1);

  // Engagement (reactions+comments per article)
  const engagement=articles.length?((totalReactions+totalComments)/articles.length).toFixed(1):0;

  // Stats grid
  $('statsGrid').innerHTML=`
    <div class="stat-card"><div class="num">${articles.length}</div><div class="label">Articles</div></div>
    <div class="stat-card"><div class="num">${fmt(totalReactions)}</div><div class="label">Reactions</div></div>
    <div class="stat-card"><div class="num">${fmt(totalComments)}</div><div class="label">Comments</div></div>
    <div class="stat-card"><div class="num">${avgReactions}</div><div class="label">Avg Reactions</div></div>
    <div class="stat-card"><div class="num">${avgComments}</div><div class="label">Avg Comments</div></div>
    <div class="stat-card"><div class="num">${articlesPerWeek}</div><div class="label">Per Week</div></div>
  `;

  // Top articles by reactions
  const sorted=[...articles].sort((a,b)=>b.positive_reactions_count-a.positive_reactions_count);
  $('topArticles').innerHTML=sorted.slice(0,10).map(a=>`
    <div class="article-row">
      <a class="article-title" href="${a.url}" target="_blank">${esc(a.title)}</a>
      <div class="article-metrics">
        <span>${a.positive_reactions_count} reactions</span>
        <span>${a.comments_count} comments</span>
      </div>
    </div>
  `).join('');

  // Tag analysis
  const tagMap={};
  articles.forEach(a=>{
    (a.tag_list||[]).forEach(t=>{
      if(!tagMap[t])tagMap[t]={count:0,reactions:0,comments:0};
      tagMap[t].count++;
      tagMap[t].reactions+=a.positive_reactions_count;
      tagMap[t].comments+=a.comments_count;
    });
  });
  const tags=Object.entries(tagMap).sort((a,b)=>b[1].count-a[1].count).slice(0,20);
  $('tagGrid').innerHTML=tags.map(([t,d])=>
    `<div class="tag-chip">#${t} <span class="tag-count">${d.count} articles · ${d.reactions} reactions</span></div>`
  ).join('');

  // Monthly chart
  const monthMap={};
  articles.forEach(a=>{
    const d=new Date(a.published_at);
    const key=d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0');
    monthMap[key]=(monthMap[key]||0)+1;
  });
  const months=Object.entries(monthMap).sort((a,b)=>a[0].localeCompare(b[0]));
  const maxMonth=Math.max(...months.map(m=>m[1]));
  $('monthChart').innerHTML=months.slice(-12).map(([m,c])=>`
    <div class="bar-row">
      <div class="bar-label">${m.slice(5)}</div>
      <div class="bar-track">
        <div class="bar-fill" style="width:${(c/maxMonth*100)}%;background:#3b82f6"></div>
        <div class="bar-val">${c}</div>
      </div>
    </div>
  `).join('');

  // Day of week chart
  const dayNames=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const dayCounts=[0,0,0,0,0,0,0];
  articles.forEach(a=>{dayCounts[new Date(a.published_at).getDay()]++});
  const maxDay=Math.max(...dayCounts);
  const colors=['#ef4444','#f59e0b','#10b981','#3b82f6','#8b5cf6','#ec4899','#ef4444'];
  $('dayChart').innerHTML=dayNames.map((name,i)=>`
    <div class="bar-row">
      <div class="bar-label">${name}</div>
      <div class="bar-track">
        <div class="bar-fill" style="width:${(dayCounts[i]/maxDay*100)}%;background:${colors[i]}"></div>
        <div class="bar-val">${dayCounts[i]}</div>
      </div>
    </div>
  `).join('');

  // Insights
  const bestTag=tags.length?tags.reduce((a,b)=>(b[1].reactions/b[1].count)>(a[1].reactions/a[1].count)?b:a):null;
  const bestDay=dayNames[dayCounts.indexOf(Math.max(...dayCounts))];
  const topArticle=sorted[0];
  const recentArticles=articles.filter(a=>new Date(a.published_at)>new Date(Date.now()-30*24*60*60*1000));
  const recentAvg=recentArticles.length?(recentArticles.reduce((s,a)=>s+a.positive_reactions_count,0)/recentArticles.length).toFixed(1):0;
  const overallAvg=avgReactions;

  const insights=[];
  insights.push(`${articles.length} articles across ${daySpan} days (${articlesPerWeek}/week)`);
  if(topArticle)insights.push(`Best performer: "${topArticle.title.slice(0,50)}..." (${topArticle.positive_reactions_count} reactions)`);
  if(bestTag)insights.push(`Highest-performing tag: #${bestTag[0]} (${(bestTag[1].reactions/bestTag[1].count).toFixed(1)} avg reactions)`);
  insights.push(`Most active day: ${bestDay}`);
  if(recentArticles.length>=3){
    const trend=recentAvg>overallAvg?'trending up':'trending down';
    insights.push(`Last 30 days: ${recentAvg} avg reactions (${trend} vs ${overallAvg} overall)`);
  }

  $('insights').innerHTML=`<h3>Insights for @${esc(user)}</h3><ul>${insights.map(i=>`<li>${i}</li>`).join('')}</ul>`;

  // Share button
  const shareText=`My dev.to stats: ${articles.length} articles, ${totalReactions} reactions, ${totalComments} comments. Top tag: #${tags.length?tags[0][0]:''}`;
  $('shareBtn').href=`https://x.com/intent/tweet?text=${encodeURIComponent(shareText)}&url=${encodeURIComponent('https://gokuscraper.github.io/dev-vault/devto-stats/')}`;
}

function fmt(n){return n>=1000?(n/1000).toFixed(1)+'K':n.toString()}
function esc(s){const d=document.createElement('div');d.textContent=s;return d.innerHTML}

// Auto-analyze if URL has ?user=xxx
const params=new URLSearchParams(location.search);
if(params.get('user')){$('username').value=params.get('user');analyze()}
</script>
