body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;background:var(--bg);color:var(--text);min-height:100vh}
.container{max-width:800px;margin:0 auto;padding:24px 16px}
h1{font-size:1.8rem;font-weight:700;text-align:center;margin-bottom:4px}
.subtitle{text-align:center;color:var(--text2);margin-bottom:32px;font-size:.95rem}
.color-inputs{display:flex;gap:24px;margin-bottom:24px;flex-wrap:wrap}
.color-group{flex:1;min-width:200px;background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:16px}
.color-group h3{font-size:.85rem;color:var(--text2);margin-bottom:10px;font-weight:500}
.color-row{display:flex;gap:10px;align-items:center}
.color-row input[type=color]{width:48px;height:40px;border:none;border-radius:8px;cursor:pointer;background:none;padding:0}
.color-row input[type=text]{flex:1;padding:8px 12px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:'SF Mono',Consolas,monospace;font-size:.95rem;outline:none}
.color-row input[type=text]:focus{border-color:var(--accent)}
.swap-btn{align-self:center;padding:8px 16px;background:var(--surface);border:1px solid var(--border);border-radius:8px;color:var(--text2);font-size:1.2rem;cursor:pointer;transition:all .2s}
.swap-btn:hover{border-color:var(--accent);color:var(--accent)}
.ratio-display{text-align:center;padding:24px;background:var(--surface);border:1px solid var(--border);border-radius:16px;margin-bottom:24px}
.ratio-number{font-size:3rem;font-weight:800;margin-bottom:4px}
.ratio-label{color:var(--text2);font-size:.9rem}
.compliance{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px;margin-bottom:24px}
.comp-card{background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:16px;text-align:center}
.comp-card .level{font-size:.82rem;color:var(--text2);margin-bottom:6px;font-weight:500}
.comp-card .result{font-size:1.3rem;font-weight:700}
.comp-card .detail{font-size:.78rem;color:var(--text2);margin-top:4px}
.pass{color:var(--green)}
.fail{color:var(--red)}
.preview-section{margin-bottom:24px}
.preview-section h3{font-size:1rem;margin-bottom:12px}
.preview-box{border-radius:12px;padding:24px;border:1px solid var(--border)}
.preview-large{font-size:24px;font-weight:700;margin-bottom:8px}
.preview-normal{font-size:16px;margin-bottom:8px}
.preview-small{font-size:12px;margin-bottom:12px}
.preview-ui{display:flex;gap:12px;flex-wrap:wrap}
.preview-btn{padding:8px 20px;border-radius:8px;font-size:.9rem;font-weight:600;border:2px solid;cursor:default}
.preview-icon{width:40px;height:40px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:1.2rem}
.presets{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:24px}
.presets button{padding:6px 14px;background:var(--surface);border:1px solid var(--border);border-radius:20px;color:var(--text2);font-size:.82rem;cursor:pointer;transition:all .2s}
.presets button:hover{border-color:var(--accent);color:var(--accent)}
.suggestions{margin-bottom:24px;background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:16px;display:none}
.suggestions h3{font-size:.95rem;margin-bottom:12px}
.sug-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:8px}
.sug-item{padding:8px 12px;border-radius:8px;text-align:center;cursor:pointer;font-size:.82rem;font-weight:600;transition:transform .1s;border:1px solid transparent}
.sug-item:hover{transform:scale(1.05);border-color:var(--accent)}
.sug-ratio{font-size:.72rem;font-weight:400;margin-top:2px;opacity:.8}
footer{text-align:center;padding:32px 16px;color:var(--text2);font-size:.82rem}
footer a{color:var(--accent);text-decoration:none}
@media(max-width:640px){.color-inputs{flex-direction:column}.swap-btn{align-self:stretch;text-align:center}}
</style>
</head>
