<div class="container">
<h1>CSS Flex</h1>
<p class="subtitle">Interactive flexbox playground. Adjust properties, see layout live.</p>

<div class="presets">
  <button class="preset-btn" onclick="preset('row','flex-start','stretch','nowrap',3)">Default</button>
  <button class="preset-btn" onclick="preset('row','center','center','nowrap',3)">Centered</button>
  <button class="preset-btn" onclick="preset('row','space-between','center','nowrap',4)">Nav Bar</button>
  <button class="preset-btn" onclick="preset('column','flex-start','stretch','nowrap',5)">Sidebar</button>
  <button class="preset-btn" onclick="preset('row','flex-start','stretch','wrap',8)">Grid-like</button>
  <button class="preset-btn" onclick="preset('row','center','flex-end','nowrap',3)">Footer</button>
</div>

<div class="layout">
  <div class="controls">
    <div class="ctrl-group">
      <h3>Container</h3>
      <div class="ctrl-row"><label>direction</label><select id="flexDir" onchange="update()"><option>row</option><option>row-reverse</option><option>column</option><option>column-reverse</option></select></div>
      <div class="ctrl-row"><label>justify</label><select id="justCont" onchange="update()"><option>flex-start</option><option>flex-end</option><option>center</option><option>space-between</option><option>space-around</option><option>space-evenly</option></select></div>
      <div class="ctrl-row"><label>align-items</label><select id="alignItems" onchange="update()"><option>stretch</option><option>flex-start</option><option>flex-end</option><option>center</option><option>baseline</option></select></div>
      <div class="ctrl-row"><label>flex-wrap</label><select id="flexWrap" onchange="update()"><option>nowrap</option><option>wrap</option><option>wrap-reverse</option></select></div>
      <div class="ctrl-row"><label>align-content</label><select id="alignCont" onchange="update()"><option>stretch</option><option>flex-start</option><option>flex-end</option><option>center</option><option>space-between</option><option>space-around</option></select></div>
      <div class="ctrl-row"><label>gap</label><input type="number" id="gap" value="8" min="0" max="40" onchange="update()"><span style="font-size:0.68rem;color:#555">px</span></div>
    </div>
    <div class="ctrl-group">
      <h3>Items (<span id="itemCount">3</span>)</h3>
      <div class="btn-row">
        <button class="btn" onclick="addItem()">+ Add</button>
        <button class="btn" onclick="removeItem()">- Remove</button>
      </div>
    </div>
    <div class="ctrl-group" id="itemControls">
      <h3>Selected Item: <span id="selLabel">1</span></h3>
      <div class="ctrl-row"><label>flex-grow</label><input type="number" id="itemGrow" value="0" min="0" max="10" onchange="updateItem()"></div>
      <div class="ctrl-row"><label>flex-shrink</label><input type="number" id="itemShrink" value="1" min="0" max="10" onchange="updateItem()"></div>
      <div class="ctrl-row"><label>flex-basis</label><select id="itemBasis" onchange="updateItem()"><option value="auto">auto</option><option value="0">0</option><option value="50px">50px</option><option value="100px">100px</option><option value="150px">150px</option><option value="200px">200px</option><option value="25%">25%</option><option value="33%">33%</option><option value="50%">50%</option></select></div>
      <div class="ctrl-row"><label>align-self</label><select id="itemAlign" onchange="updateItem()"><option value="auto">auto</option><option>flex-start</option><option>flex-end</option><option>center</option><option>stretch</option><option>baseline</option></select></div>
      <div class="ctrl-row"><label>order</label><input type="number" id="itemOrder" value="0" min="-5" max="10" onchange="updateItem()"></div>
      <div class="ctrl-row"><label>width</label><input type="number" id="itemW" value="80" min="20" max="300" onchange="updateItem()"><span style="font-size:0.68rem;color:#555">px</span></div>
