<style>
*{margin:0;padding:0;box-sizing:border-box}
:root{
  --bg:#0d1117;
  --surface:#161b22;
  --border:#30363d;
  --text:#e6edf3;
  --text2:#8b949e;
  --accent:#58a6ff;
  --green:#3fb950;
  --red:#f85149;
  --yellow:#d29922;
}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif;background:var(--bg);color:var(--text);min-height:100vh;font-size:14px}
a{color:var(--accent);text-decoration:none}
a:hover{text-decoration:underline}
.container{max-width:1000px;margin:0 auto;padding:24px 16px}
.back{display:inline-block;margin-bottom:20px;font-size:0.85rem;color:var(--text2)}
.back:hover{color:var(--accent)}
h1{font-size:1.6rem;font-weight:700;color:var(--text);margin-bottom:4px}
.subtitle{color:var(--text2);font-size:0.88rem;margin-bottom:24px}

/* Cards */
.card{background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:16px;margin-bottom:14px}
.card-title{font-size:0.78rem;font-weight:600;color:var(--text2);text-transform:uppercase;letter-spacing:0.06em;margin-bottom:12px}

/* Tabs / Pill row */
.pill-row{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:12px}
.pill{padding:5px 12px;border-radius:20px;border:1px solid var(--border);background:var(--bg);color:var(--text2);font-size:0.8rem;cursor:pointer;transition:all 0.15s;white-space:nowrap}
.pill:hover{border-color:var(--accent);color:var(--accent)}
.pill.active{background:#1f3a5f;border-color:var(--accent);color:var(--accent)}

/* Type selector */
.type-row{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px}
.type-btn{padding:6px 14px;border-radius:6px;border:1px solid var(--border);background:var(--bg);color:var(--text2);font-size:0.82rem;cursor:pointer;font-weight:600;transition:all 0.15s}
.type-btn:hover{border-color:var(--accent);color:var(--accent)}
.type-btn.active{background:#1f3a5f;border-color:var(--accent);color:var(--accent)}
.not-toggle{padding:6px 14px;border-radius:6px;border:1px solid var(--border);background:var(--bg);color:var(--text2);font-size:0.82rem;cursor:pointer;font-weight:600;transition:all 0.15s;margin-left:auto}
.not-toggle.active{background:#3a1515;border-color:var(--red);color:var(--red)}

/* Conditions builder */
.conditions-list{display:flex;flex-direction:column;gap:8px;margin-bottom:12px}
.condition-row{display:flex;gap:8px;align-items:center;background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:10px 12px;flex-wrap:wrap}
.combinator-badge{font-size:0.7rem;font-weight:700;padding:2px 7px;border-radius:4px;background:#1f3a5f;color:var(--accent);border:1px solid var(--accent);cursor:pointer;user-select:none;flex-shrink:0}
.combinator-badge.or{background:#2a1f0f;color:var(--yellow);border-color:var(--yellow)}
select,input[type="text"],input[type="number"]{background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);padding:5px 8px;font-size:0.82rem;outline:none;transition:border-color 0.15s}
select:focus,input[type="text"]:focus,input[type="number"]:focus{border-color:var(--accent)}
select{cursor:pointer}
.feat-select{min-width:170px}
.val-input{width:90px}
.val-unit{width:65px}
.remove-btn{background:none;border:1px solid var(--border);color:var(--text2);border-radius:6px;padding:4px 8px;cursor:pointer;font-size:0.75rem;flex-shrink:0;transition:all 0.15s;margin-left:auto}
.remove-btn:hover{border-color:var(--red);color:var(--red)}
.add-condition-btn{padding:7px 14px;border-radius:6px;border:1px dashed var(--border);background:transparent;color:var(--text2);font-size:0.82rem;cursor:pointer;transition:all 0.15s;width:100%}
.add-condition-btn:hover{border-color:var(--accent);color:var(--accent)}

/* Output */
.output-block{background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:14px;font-family:'SFMono-Regular',Consolas,'Liberation Mono',Menlo,monospace;font-size:0.85rem;line-height:1.7;white-space:pre;overflow-x:auto;color:var(--text);cursor:pointer;transition:border-color 0.2s;position:relative}
.output-block:hover{border-color:var(--accent)}
.kw{color:#ff7b72}
.at{color:var(--accent)}
.feat{color:#ffa657}
.val{color:var(--green)}
.prop{color:#79c0ff}
.cmt{color:var(--text2)}
.copy-btn{position:absolute;top:10px;right:10px;padding:5px 12px;border-radius:6px;border:1px solid var(--border);background:var(--surface);color:var(--text2);font-size:0.78rem;cursor:pointer;transition:all 0.2s}
.copy-btn:hover{border-color:var(--accent);color:var(--accent)}
.copy-btn.copied{border-color:var(--green);color:var(--green)}

/* Live preview */
.live-preview-wrap{border-radius:8px;border:1px solid var(--border);overflow:hidden;margin-bottom:14px}
.live-preview-inner{padding:20px;background:var(--bg);display:flex;align-items:center;justify-content:center;min-height:130px}
.preview-box{border-radius:8px;padding:20px 28px;text-align:center;transition:all 0.3s;font-size:0.9rem;font-weight:600}
.preview-box.matched{background:#1f3a5f;border:2px solid var(--accent);color:var(--accent)}
.preview-box.unmatched{background:#1a1f1a;border:2px dashed var(--border);color:var(--text2)}
.match-indicator{display:flex;align-items:center;gap:6px;font-size:0.8rem;padding:10px 14px;border-top:1px solid var(--border);background:var(--surface)}
.dot{width:8px;height:8px;border-radius:50%;flex-shrink:0}
.dot.green{background:var(--green)}
.dot.red{background:var(--red)}
.match-label{color:var(--text2)}
.match-label strong{color:var(--text)}

/* Breakpoint visualizer */
.bpviz{position:relative;height:48px;background:var(--bg);border-radius:8px;border:1px solid var(--border);overflow:visible;margin-bottom:4px}
.bpviz-track{position:absolute;top:50%;left:0;right:0;height:3px;background:var(--border);transform:translateY(-50%);border-radius:2px}
.bpviz-fill{position:absolute;top:50%;height:3px;background:var(--accent);transform:translateY(-50%);border-radius:2px;transition:all 0.3s;opacity:0.4}
