.diff-line.removed { background: #f8514920; border-left: 3px solid var(--red); }
.diff-line.same { border-left: 3px solid transparent; }

.line-num {
  color: var(--text2);
  min-width: 36px;
  user-select: none;
  font-size: 11px;
  padding-top: 1px;
