  margin-bottom: 12px;
  font-size: 12px;
  color: var(--text2);
}
.legend-item { display: flex; align-items: center; gap: 6px; }
.legend-dot { width: 10px; height: 10px; border-radius: 2px; }
.legend-dot.added { background: var(--green); }
.legend-dot.removed { background: var(--red); }
.legend-dot.same { background: var(--border); }

.diff-stats {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 12px 20px;
  margin-bottom: 16px;
  display: flex;
  gap: 24px;
  font-size: 13px;
}
.stat-item { color: var(--text2); }
.stat-item span { font-weight: 600; }
.stat-item .added-count { color: var(--green); }
.stat-item .removed-count { color: var(--red); }

/* Builder tab */
.builder-layout {
  display: grid;
  grid-template-columns: 340px 1fr;
  gap: 24px;
}

.builder-options {
