}

.options-group {
  padding: 12px 16px;
  border-bottom: 1px solid var(--border);
}

.options-group:last-child { border-bottom: none; }

.group-title {
  color: var(--text2);
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 10px;
  font-weight: 500;
}

.option-item {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  padding: 6px 0;
  cursor: pointer;
