.option-text { flex: 1; }
.option-label { font-size: 13px; color: var(--text); display: block; }
.option-hint { font-size: 11px; color: var(--text2); }

.builder-preview {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
}

.preview-header {
  padding: 14px 16px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
