.preview-empty {
  padding: 60px 20px;
  text-align: center;
  color: var(--text2);
}
.preview-empty-icon { font-size: 48px; margin-bottom: 12px; opacity: 0.4; }

/* Count badge */
.count-badge {
  background: var(--accent)22;
  border: 1px solid var(--accent)44;
  border-radius: 12px;
  color: var(--accent);
  font-size: 11px;
  padding: 1px 8px;
}

/* Utility */
.mt8 { margin-top: 8px; }
.mt16 { margin-top: 16px; }
.mt24 { margin-top: 24px; }
.flex { display: flex; }
.gap8 { gap: 8px; }
.items-center { align-items: center; }

/* Scrollbar */
::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: var(--text2); }

/* Responsive */
@media (max-width: 768px) {
  .compare-selects { grid-template-columns: 1fr; }
  .compare-vs { display: none; }
  .compare-panes { grid-template-columns: 1fr; }
  .builder-layout { grid-template-columns: 1fr; }
  .builder-options { position: static; }
  .resets-grid { grid-template-columns: 1fr; }
}
</style>
