  .tuple-display {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 16px;
    flex-wrap: wrap;
  }

  .tuple {
    font-family: 'SFMono-Regular', Consolas, monospace;
    font-size: 28px;
    font-weight: 700;
    color: var(--text);
    letter-spacing: 2px;
  }

  .selector-echo {
    font-family: 'SFMono-Regular', Consolas, monospace;
    font-size: 13px;
    color: var(--text2);
    background: var(--bg);
    padding: 4px 10px;
    border-radius: 4px;
    border: 1px solid var(--border);
  }

  .breakdown-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 12px;
    margin-bottom: 18px;
  }

  .breakdown-cell {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 14px 12px;
    text-align: center;
  }

  .breakdown-cell .label {
    font-size: 11px;
    color: var(--text2);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-bottom: 4px;
  }

  .breakdown-cell .count {
    font-size: 30px;
    font-weight: 700;
    line-height: 1;
  }

  .breakdown-cell .sublabel {
    font-size: 11px;
    color: var(--text2);
    margin-top: 4px;
  }

  .breakdown-cell.inline .count { color: var(--purple); }
  .breakdown-cell.ids .count { color: var(--seg-id); }
  .breakdown-cell.classes .count { color: var(--seg-class); }
  .breakdown-cell.elems .count { color: var(--seg-elem); }

  /* Bar */
  .bar-container {
    margin-bottom: 6px;
  }

  .bar-label {
    font-size: 12px;
    color: var(--text2);
    margin-bottom: 6px;
  }

  .spec-bar {
    height: 16px;
    border-radius: 4px;
    overflow: hidden;
    background: var(--bg);
    display: flex;
    border: 1px solid var(--border);
    min-height: 16px;
  }

  .spec-bar .seg {
    height: 100%;
    transition: width 0.3s ease;
    position: relative;
  }

  .seg.inline-seg { background: var(--purple); }
  .seg.id-seg { background: var(--seg-id); }
  .seg.class-seg { background: var(--seg-class); }
  .seg.elem-seg { background: var(--seg-elem); }

  .bar-legend {
    display: flex;
    gap: 16px;
    margin-top: 8px;
    flex-wrap: wrap;
  }

  .legend-item {
    display: flex;
    align-items: center;
    gap: 5px;
    font-size: 12px;
    color: var(--text2);
  }

  .legend-dot {
    width: 10px;
    height: 10px;
    border-radius: 2px;
  }

  /* ── Compare ── */
  .compare-results {
    margin-top: 18px;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }

  .compare-row {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 14px 16px;
    display: grid;
    grid-template-columns: 1fr auto;
    gap: 12px;
    align-items: start;
  }

  .compare-row.winner {
    border-color: var(--green);
    box-shadow: 0 0 0 1px var(--green) inset;
  }

  .compare-row .selector-text {
    font-family: 'SFMono-Regular', Consolas, monospace;
    font-size: 13px;
    color: var(--text);
    word-break: break-all;
    margin-bottom: 8px;
  }

  .compare-row .row-tuple {
    font-family: 'SFMono-Regular', Consolas, monospace;
    font-size: 13px;
    color: var(--text2);
    margin-bottom: 8px;
  }

  .compare-row .row-bar {
    height: 10px;
    border-radius: 3px;
    overflow: hidden;
    background: rgba(255,255,255,0.05);
    display: flex;
    border: 1px solid var(--border);
  }

  .winner-badge {
    background: var(--green);
    color: #0d1117;
    font-size: 11px;
    font-weight: 700;
    padding: 2px 8px;
    border-radius: 4px;
    white-space: nowrap;
    align-self: flex-start;
  }

  .rank-num {
    font-size: 11px;
    color: var(--text2);
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 2px 7px;
    align-self: flex-start;
    white-space: nowrap;
  }

  /* ── Quiz ── */
  .quiz-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 14px;
  }

  @media (max-width: 600px) {
    .quiz-grid { grid-template-columns: 1fr; }
    .breakdown-grid { grid-template-columns: repeat(2, 1fr); }
  }

  .quiz-card {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 16px;
  }

  .quiz-card .q-label {
    font-size: 11px;
    color: var(--text2);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-bottom: 8px;
  }

  .quiz-selectors {
    display: flex;
    flex-direction: column;
    gap: 6px;
    margin-bottom: 12px;
  }

  .quiz-sel {
    font-family: 'SFMono-Regular', Consolas, monospace;
    font-size: 13px;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 6px 10px;
    color: var(--text);
  }

  .quiz-answer {
    display: none;
    margin-top: 10px;
    padding: 10px 12px;
    background: rgba(63, 185, 80, 0.08);
    border: 1px solid rgba(63, 185, 80, 0.25);
    border-radius: 6px;
    font-size: 13px;
  }

  .quiz-answer.visible { display: block; }

  .quiz-answer .winner-sel {
    font-family: 'SFMono-Regular', Consolas, monospace;
    color: var(--green);
    font-weight: 600;
  }

  .quiz-answer .explanation {
    color: var(--text2);
    font-size: 12px;
    margin-top: 4px;
  }

  button.reveal-btn {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--text2);
    font-size: 12px;
    padding: 5px 12px;
    border-radius: 5px;
    font-weight: 500;
  }
  button.reveal-btn:hover { border-color: var(--accent); color: var(--accent); }

  /* ── Cheatsheet ── */
  .cheat-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 18px;
  }

  @media (max-width: 600px) { .cheat-grid { grid-template-columns: 1fr; } }

  .cheat-section h3 {
    font-size: 13px;
    font-weight: 600;
    color: var(--text2);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-bottom: 10px;
  }

  .cheat-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 13px;
  }

  .cheat-table td {
    padding: 5px 8px;
    border-bottom: 1px solid rgba(48, 54, 61, 0.5);
    vertical-align: middle;
  }

  .cheat-table td:first-child {
    font-family: 'SFMono-Regular', Consolas, monospace;
    color: var(--text);
    width: 55%;
  }

  .cheat-table td:last-child {
    color: var(--text2);
    font-size: 12px;
  }

  .cheat-table .tag {
    display: inline-block;
    font-size: 10px;
    padding: 1px 5px;
    border-radius: 3px;
    font-family: -apple-system, system-ui, sans-serif;
    font-weight: 600;
  }

  .tag.id { background: rgba(248, 81, 73, 0.2); color: var(--seg-id); }
  .tag.cls { background: rgba(210, 153, 34, 0.2); color: var(--seg-class); }
  .tag.el { background: rgba(88, 166, 255, 0.2); color: var(--seg-elem); }
  .tag.zero { background: rgba(139, 148, 158, 0.2); color: var(--text2); }

  .rule-list {
    list-style: none;
    display: flex;
    flex-direction: column;
    gap: 7px;
  }

  .rule-list li {
    font-size: 13px;
    color: var(--text2);
    padding-left: 16px;
    position: relative;
    line-height: 1.5;
  }

  .rule-list li::before {
    content: '→';
    position: absolute;
    left: 0;
    color: var(--accent);
    font-size: 11px;
    top: 1px;
  }

  .rule-list li code {
    font-family: 'SFMono-Regular', Consolas, monospace;
    font-size: 12px;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 3px;
    padding: 0 4px;
    color: var(--text);
  }

  /* ── Error ── */
  .error-msg {
    font-size: 12px;
    color: var(--red);
    margin-top: 6px;
    display: none;
  }
  .error-msg.visible { display: block; }

  /* ── Empty state ── */
  .empty-hint {
    font-size: 13px;
    color: var(--text2);
    text-align: center;
    padding: 20px;
  }

  /* ── Divider ── */
  hr.divider {
    border: none;
    border-top: 1px solid var(--border);
    margin: 18px 0;
  }
</style>
</head>
