<style>
  :root {
    --bg: #0d1117;
    --surface: #161b22;
    --border: #30363d;
    --text: #e6edf3;
    --text2: #8b949e;
    --accent: #58a6ff;
    --green: #3fb950;
    --red: #f85149;
    --yellow: #d29922;
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    font-size: 14px;
    min-height: 100vh;
    padding: 24px;
  }

  a { color: var(--accent); text-decoration: none; }
  a:hover { text-decoration: underline; }

  .back-link {
    display: inline-block;
    margin-bottom: 20px;
    font-size: 13px;
    color: var(--text2);
  }
  .back-link:hover { color: var(--accent); }

  h1 {
    font-size: 22px;
    font-weight: 600;
    margin-bottom: 24px;
    color: var(--text);
  }

  .layout {
    display: grid;
    grid-template-columns: 380px 1fr;
    gap: 20px;
    max-width: 1200px;
  }

  .panel {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 20px;
  }

  .panel-title {
    font-size: 12px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: var(--text2);
    margin-bottom: 16px;
  }

  .field { margin-bottom: 16px; }

  label {
    display: block;
    font-size: 12px;
    color: var(--text2);
    margin-bottom: 6px;
  }

  /* Property multi-select */
  .prop-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 6px;
  }

  .prop-chip {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 6px 10px;
    font-size: 12px;
    color: var(--text2);
    cursor: pointer;
    user-select: none;
    transition: all 0.15s ease;
    text-align: center;
  }
  .prop-chip:hover { border-color: var(--accent); color: var(--text); }
  .prop-chip.active {
    background: rgba(88,166,255,0.12);
    border-color: var(--accent);
    color: var(--accent);
  }

  /* Sliders */
  .slider-row {
    display: flex;
    align-items: center;
    gap: 10px;
  }

  input[type="range"] {
    flex: 1;
    -webkit-appearance: none;
    background: var(--border);
    height: 4px;
    border-radius: 2px;
    outline: none;
  }
  input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background: var(--accent);
    cursor: pointer;
    transition: transform 0.1s;
  }
  input[type="range"]::-webkit-slider-thumb:hover { transform: scale(1.2); }
  input[type="range"]::-moz-range-thumb {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background: var(--accent);
    cursor: pointer;
    border: none;
  }

  .slider-val {
    font-size: 12px;
    color: var(--accent);
    min-width: 52px;
    text-align: right;
    font-variant-numeric: tabular-nums;
  }

  /* Timing function */
  .timing-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 6px;
    margin-bottom: 10px;
  }

  .timing-btn {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 6px 8px;
    font-size: 12px;
    color: var(--text2);
    cursor: pointer;
    text-align: center;
    transition: all 0.15s ease;
  }
  .timing-btn:hover { border-color: var(--accent); color: var(--text); }
  .timing-btn.active {
    background: rgba(88,166,255,0.12);
    border-color: var(--accent);
    color: var(--accent);
  }

  /* Cubic bezier editor */
  .bezier-section {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 14px;
    margin-top: 8px;
  }

  .bezier-canvas-wrap {
    display: flex;
    justify-content: center;
    margin-bottom: 12px;
  }

  #bezierCanvas {
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: crosshair;
    display: block;
  }

  .bezier-inputs {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr 1fr;
    gap: 8px;
  }

  .bezier-input-group { text-align: center; }
  .bezier-input-group label {
    font-size: 11px;
    margin-bottom: 4px;
    display: block;
  }
  .bezier-input-group input[type="number"] {
    width: 100%;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 4px;
    color: var(--text);
    padding: 5px 6px;
    font-size: 12px;
    text-align: center;
    outline: none;
  }
  .bezier-input-group input[type="number"]:focus { border-color: var(--accent); }

  /* Presets */
  .presets-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 6px;
  }

  .preset-btn {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 7px 10px;
    font-size: 12px;
    color: var(--text2);
    cursor: pointer;
    text-align: left;
    transition: all 0.15s ease;
  }
  .preset-btn:hover { border-color: var(--yellow); color: var(--yellow); }

  /* Multi-transitions list */
  .transitions-list { margin-bottom: 10px; }

  .transition-item {
    display: flex;
    align-items: center;
    gap: 8px;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 8px 10px;
    margin-bottom: 6px;
    font-size: 12px;
    font-family: 'SFMono-Regular', Consolas, monospace;
  }

  .transition-item-text { flex: 1; color: var(--accent); word-break: break-all; }

  .remove-btn {
    background: none;
    border: none;
    color: var(--red);
    cursor: pointer;
    font-size: 16px;
    line-height: 1;
    padding: 2px 4px;
    border-radius: 4px;
    transition: background 0.1s;
    flex-shrink: 0;
  }
  .remove-btn:hover { background: rgba(248,81,73,0.15); }

  .add-btn {
    background: rgba(63,185,80,0.1);
    border: 1px solid var(--green);
    border-radius: 6px;
    color: var(--green);
    padding: 7px 14px;
    font-size: 12px;
    cursor: pointer;
    width: 100%;
    transition: background 0.15s;
  }
  .add-btn:hover { background: rgba(63,185,80,0.2); }

  /* Right column */
  .right-col {
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  /* Preview */
  .preview-area {
    min-height: 200px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: repeating-conic-gradient(var(--bg) 0% 25%, transparent 0% 50%) 0 0 / 20px 20px;
    border-radius: 8px;
    border: 1px solid var(--border);
    overflow: hidden;
    position: relative;
  }

  #previewBox {
    width: 100px;
    height: 100px;
    background: var(--accent);
    border-radius: 8px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 12px;
    color: rgba(255,255,255,0.7);
    user-select: none;
    /* transition injected by JS */
  }

  .preview-hint {
    position: absolute;
    bottom: 10px;
    right: 12px;
    font-size: 11px;
    color: var(--text2);
  }

  /* Preset visual demos */
  #previewBox.preset-fade { opacity: 1; }
  #previewBox.preset-fade:hover { opacity: 0; }
  #previewBox.preset-slide:hover { transform: translateX(60px); }
  #previewBox.preset-scale:hover { transform: scale(1.5); }
  #previewBox.preset-color:hover { background: var(--green); }
  #previewBox.preset-blur:hover { filter: blur(6px); }
  #previewBox.preset-bounce:hover { transform: translateY(-40px); }
  #previewBox.preset-elastic:hover { transform: scaleX(1.6) scaleY(0.6); }
  #previewBox.preset-shadow:hover { box-shadow: 0 20px 60px rgba(88,166,255,0.6); }
  #previewBox.preset-rotate:hover { transform: rotate(180deg); }
  #previewBox.preset-multi:hover { transform: scale(1.3) rotate(15deg); background: var(--yellow); box-shadow: 0 10px 40px rgba(210,153,34,0.5); }

  /* Output */
  .output-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 10px;
  }

  .copy-btn {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text2);
    padding: 5px 12px;
    font-size: 12px;
    cursor: pointer;
    transition: all 0.15s;
  }
  .copy-btn:hover { border-color: var(--accent); color: var(--accent); }
  .copy-btn.copied { border-color: var(--green); color: var(--green); }

  .output-code {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 14px;
    font-family: 'SFMono-Regular', Consolas, 'Liberation Mono', monospace;
    font-size: 13px;
    line-height: 1.7;
    white-space: pre-wrap;
    word-break: break-all;
    min-height: 80px;
    color: var(--text);
  }

  .css-prop { color: var(--accent); }
  .css-val  { color: var(--green); }
  .css-punc { color: var(--text2); }

  /* Responsive */
  @media (max-width: 800px) {
    .layout { grid-template-columns: 1fr; }
    body { padding: 16px; }
  }
</style>
</head>
