<style>
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: #0a0a0a;
  --bg-elevated: #141414;
  --bg-surface: #1a1a1a;
  --bg-input: #222222;
  --border: #2a2a2a;
  --border-hover: #3a3a3a;
  --text: #e6e6e6;
  --text-secondary: #999;
  --text-dim: #666;
  --accent: #3b82f6;
  --accent-hover: #2563eb;
  --accent-glow: rgba(59, 130, 246, 0.15);
  --green: #22c55e;
  --orange: #f59e0b;
  --red: #ef4444;
  --purple: #a855f7;
  --cyan: #06b6d4;
  --radius: 8px;
  --radius-lg: 12px;
  --font: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --mono: 'JetBrains Mono', 'Fira Code', monospace;
}

html { font-size: 14px; }
body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
}

/* Header */
.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 24px;
  border-bottom: 1px solid var(--border);
  background: var(--bg-elevated);
}
.header h1 {
  font-size: 1.15rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 10px;
}
.header h1 .icon {
  width: 28px;
  height: 28px;
  background: var(--purple);
  border-radius: 6px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
}
.header .links {
  display: flex;
  gap: 12px;
  align-items: center;
}
.header .links a {
  font-size: 0.8rem;
  color: var(--text-secondary);
  text-decoration: none;
}
.header .links a:hover { color: var(--text); }

/* Layout */
.app {
  display: flex;
  height: calc(100vh - 57px);
}
.controls-panel {
  width: 400px;
  min-width: 400px;
  border-right: 1px solid var(--border);
  overflow-y: auto;
  background: var(--bg-elevated);
  display: flex;
  flex-direction: column;
}
.main-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* Preset bar */
.presets {
  padding: 16px 20px;
  border-bottom: 1px solid var(--border);
}
.presets h3 {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-dim);
  margin-bottom: 10px;
}
.preset-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
}
.preset-btn {
  padding: 8px 12px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--bg-surface);
  color: var(--text-secondary);
  font-size: 0.78rem;
  cursor: pointer;
  text-align: left;
  font-family: var(--font);
  transition: all 0.15s;
}
.preset-btn:hover {
  border-color: var(--border-hover);
  color: var(--text);
}
.preset-btn.active {
  border-color: var(--purple);
  background: rgba(168, 85, 247, 0.1);
  color: var(--purple);
}
.preset-btn .preset-title {
  font-weight: 600;
  display: block;
  margin-bottom: 2px;
}
.preset-btn .preset-desc {
  font-size: 0.68rem;
  color: var(--text-dim);
}
.preset-btn.active .preset-desc { color: rgba(168, 85, 247, 0.7); }

/* Code editors */
.editor-section {
  flex: 1;
  overflow-y: auto;
  padding: 0;
}
.editor-group {
  border-bottom: 1px solid var(--border);
}
.editor-label {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 20px;
  background: var(--bg-surface);
  cursor: pointer;
  user-select: none;
}
.editor-label h4 {
  font-size: 0.78rem;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 8px;
}
.editor-label .dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
}
.editor-label .arrow {
  font-size: 0.65rem;
  color: var(--text-dim);
  transition: transform 0.2s;
}
.editor-label.collapsed .arrow { transform: rotate(-90deg); }
.editor-wrapper {
  position: relative;
}
.editor-wrapper textarea {
  width: 100%;
  min-height: 120px;
  padding: 12px 20px;
  background: var(--bg);
  border: none;
  color: var(--text);
  font-family: var(--mono);
  font-size: 0.82rem;
  line-height: 1.6;
  resize: vertical;
  outline: none;
  tab-size: 2;
}
.editor-wrapper textarea:focus {
  background: #0d0d0d;
}

/* Run button */
.run-bar {
  padding: 12px 20px;
  border-top: 1px solid var(--border);
  display: flex;
  gap: 8px;
  align-items: center;
}
.run-btn {
  padding: 8px 20px;
  background: var(--purple);
  color: #fff;
  border: none;
  border-radius: var(--radius);
  font-family: var(--font);
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s;
}
.run-btn:hover { background: #9333ea; }
.auto-run {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 0.75rem;
  color: var(--text-dim);
}
.auto-run input { accent-color: var(--purple); }

/* Main panel tabs */
.panel-tabs {
  display: flex;
  border-bottom: 1px solid var(--border);
  background: var(--bg-elevated);
}
.panel-tab {
  padding: 10px 20px;
  font-size: 0.8rem;
  font-weight: 500;
  color: var(--text-dim);
  cursor: pointer;
  border-bottom: 2px solid transparent;
  font-family: var(--font);
  background: none;
  border-top: none;
  border-left: none;
  border-right: none;
}
.panel-tab:hover { color: var(--text-secondary); }
.panel-tab.active {
  color: var(--purple);
  border-bottom-color: var(--purple);
}

/* Preview */
.preview-area {
  flex: 1;
  overflow: auto;
  position: relative;
}
.preview-content {
  padding: 24px;
  min-height: 100%;
}

/* Tree view */
.tree-view {
  padding: 24px;
  overflow: auto;
  flex: 1;
  display: none;
  font-family: var(--mono);
  font-size: 0.82rem;
  line-height: 1.8;
}
.tree-view.active { display: block; }

.tree-node {
  padding-left: 20px;
  border-left: 1px solid var(--border);
  margin-left: 4px;
}
.tree-node-label {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 2px 8px;
  border-radius: 4px;
  cursor: default;
}
.tree-node-label:hover { background: var(--bg-surface); }
.tree-tag { color: var(--cyan); }
.tree-shadow { color: var(--purple); font-weight: 600; }
.tree-slot { color: var(--orange); }
.tree-text { color: var(--text-dim); font-style: italic; }
.tree-attr { color: var(--green); }
.tree-boundary {
  display: inline-block;
  font-size: 0.65rem;
  padding: 1px 6px;
  border-radius: 3px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
.boundary-shadow {
  background: rgba(168, 85, 247, 0.15);
  color: var(--purple);
  border: 1px solid rgba(168, 85, 247, 0.3);
}
.boundary-slot {
  background: rgba(245, 158, 11, 0.15);
  color: var(--orange);
  border: 1px solid rgba(245, 158, 11, 0.3);
}

/* Info panel */
.info-panel {
  padding: 24px;
  overflow: auto;
  flex: 1;
  display: none;
}
.info-panel.active { display: block; }
.info-card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 20px;
  margin-bottom: 16px;
}
.info-card h3 {
  font-size: 0.9rem;
  margin-bottom: 10px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.info-card p, .info-card li {
  font-size: 0.82rem;
  color: var(--text-secondary);
  line-height: 1.7;
}
.info-card ul {
  padding-left: 20px;
}
.info-card code {
  font-family: var(--mono);
  background: var(--bg-input);
  padding: 2px 6px;
  border-radius: 3px;
  font-size: 0.78rem;
  color: var(--cyan);
}

/* Status bar */
.status-bar {
  padding: 8px 20px;
  border-top: 1px solid var(--border);
