*{margin:0;padding:0;box-sizing:border-box}
:root{
  --bg:#0d1117;--surface:#161b22;--border:#30363d;
  --text:#e6edf3;--text2:#8b949e;
  --accent:#58a6ff;--green:#3fb950;--red:#f85149;--yellow:#d29922;
}
body{font-family:system-ui,-apple-system,sans-serif;background:var(--bg);color:var(--text);min-height:100vh;display:flex;flex-direction:column;font-size:14px;line-height:1.6}
/* Header */
header{background:var(--surface);border-bottom:1px solid var(--border);padding:14px 24px;display:flex;align-items:baseline;gap:12px}
header h1{font-size:17px;font-weight:700}
header .sub{color:var(--text2);font-size:12px}
/* Layout */
main{max-width:1100px;width:100%;margin:0 auto;padding:20px 16px 40px;flex:1;display:flex;flex-direction:column;gap:18px}
/* Input area */
.input-card{background:var(--surface);border:1px solid var(--border);border-radius:8px;overflow:hidden}
.input-toolbar{display:flex;align-items:center;justify-content:space-between;padding:9px 14px;border-bottom:1px solid var(--border);gap:8px;flex-wrap:wrap}
.input-label{font-size:11px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.06em}
.btn-group{display:flex;gap:6px}
button{background:var(--bg);color:var(--text);border:1px solid var(--border);border-radius:6px;padding:5px 13px;font-size:12px;font-family:inherit;cursor:pointer;transition:border-color .15s,background .15s}
button:hover{border-color:var(--text2);background:#1c2128}
button.primary{background:var(--accent);color:#000;border-color:var(--accent);font-weight:600}
button.primary:hover{opacity:.85}
textarea{width:100%;min-height:200px;background:transparent;border:none;outline:none;color:var(--text);font-family:inherit;font-size:15px;line-height:1.7;padding:14px;resize:vertical}
textarea::placeholder{color:var(--text2)}
/* Stats grid */
.stats-grid{display:grid;grid-template-columns:repeat(6,1fr);gap:10px}
.stat-card{background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:12px 14px}
.stat-val{font-size:24px;font-weight:700;color:var(--accent);line-height:1.1}
.stat-lbl{font-size:11px;color:var(--text2);margin-top:3px;font-weight:500}
/* Time + Bytes row */
.meta-row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px}
.meta-card{background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:12px 14px;display:flex;align-items:center;gap:12px}
.meta-icon{font-size:20px;flex-shrink:0}
.meta-val{font-size:17px;font-weight:700;color:var(--text)}
.meta-lbl{font-size:11px;color:var(--text2);margin-top:2px}
/* Section heading */
.section-h{font-size:11px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px}
/* Platform grid */
.platforms-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:10px}
.plat-card{background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:11px 13px}
.plat-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:7px;gap:6px}
.plat-name{font-size:13px;font-weight:600;white-space:nowrap}
.plat-count{font-size:12px;font-weight:600;white-space:nowrap;color:var(--text2)}
.plat-count.ok{color:var(--green)}
.plat-count.warn{color:var(--yellow)}
.plat-count.over{color:var(--red)}
.progress-track{height:6px;background:var(--border);border-radius:3px;overflow:hidden}
.progress-fill{height:100%;border-radius:3px;transition:width .18s ease,background .18s ease;background:var(--green)}
.progress-fill.warn{background:var(--yellow)}
.progress-fill.over{background:var(--red)}
/* Analysis section */
.analysis-row{display:grid;grid-template-columns:1fr 1fr;gap:18px}
.card{background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:14px}
/* Word frequency */
.word-list{display:flex;flex-direction:column;gap:5px;margin-top:4px}
.word-row{display:grid;grid-template-columns:22px 1fr auto;align-items:center;gap:8px}
.word-rank{font-size:10px;font-weight:700;color:var(--text2);text-align:right}
.word-bar-wrap{position:relative;height:22px;background:var(--bg);border-radius:4px;overflow:hidden;display:flex;align-items:center}
.word-bar-bg{position:absolute;inset:0;background:rgba(88,166,255,.14);border-radius:4px;transition:width .25s ease}
.word-txt{position:relative;padding:0 7px;font-size:13px;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:180px}
.word-cnt{font-size:11px;font-weight:700;color:var(--text2);white-space:nowrap}
/* Collapsible */
.coll-header{display:flex;justify-content:space-between;align-items:center;cursor:pointer;user-select:none}
.coll-arrow{color:var(--text2);font-size:12px;transition:transform .2s}
.coll-header.open .coll-arrow{transform:rotate(180deg)}
.coll-body{display:none;margin-top:12px}
.coll-body.open{display:block}
