  .analysis-row{grid-template-columns:1fr}
  .stats-grid{grid-template-columns:repeat(3,1fr)}
  .meta-row{grid-template-columns:1fr 1fr}
}
@media(max-width:580px){
  .stats-grid{grid-template-columns:repeat(2,1fr)}
