<body>

<header>
  <h1>Character Counter</h1>
  <span class="sub">Live stats · 10 platform limits · word & character frequency</span>
</header>

<main>

  <!-- Textarea -->
  <div class="input-card">
    <div class="input-toolbar">
      <span class="input-label">Your Text</span>
      <div class="btn-group">
        <button id="copyBtn" onclick="copyText()">Copy Text</button>
        <button onclick="clearText()">Clear</button>
      </div>
    </div>
    <textarea id="textInput" placeholder="Start typing or paste your text here…" oninput="update()" autofocus></textarea>
  </div>

  <!-- Core stats -->
  <div class="stats-grid">
    <div class="stat-card"><div class="stat-val" id="sChars">0</div><div class="stat-lbl">Characters</div></div>
    <div class="stat-card"><div class="stat-val" id="sCharsNS">0</div><div class="stat-lbl">Chars (no spaces)</div></div>
    <div class="stat-card"><div class="stat-val" id="sWords">0</div><div class="stat-lbl">Words</div></div>
    <div class="stat-card"><div class="stat-val" id="sSentences">0</div><div class="stat-lbl">Sentences</div></div>
    <div class="stat-card"><div class="stat-val" id="sParas">0</div><div class="stat-lbl">Paragraphs</div></div>
    <div class="stat-card"><div class="stat-val" id="sLines">0</div><div class="stat-lbl">Lines</div></div>
  </div>

  <!-- Reading time + bytes -->
  <div class="meta-row">
    <div class="meta-card">
      <div class="meta-icon">📖</div>
      <div><div class="meta-val" id="mRead">0 sec</div><div class="meta-lbl">Reading time (200 wpm)</div></div>
    </div>
    <div class="meta-card">
      <div class="meta-icon">🎙️</div>
      <div><div class="meta-val" id="mSpeak">0 sec</div><div class="meta-lbl">Speaking time (130 wpm)</div></div>
    </div>
    <div class="meta-card">
      <div class="meta-icon">💾</div>
      <div><div class="meta-val" id="mBytes">0 B</div><div class="meta-lbl">Byte size (UTF-8)</div></div>
    </div>
  </div>

  <!-- Platform limits -->
  <div>
    <div class="section-h">Platform Limits</div>
    <div class="platforms-grid" id="platformsGrid"></div>
  </div>

  <!-- Analysis -->
  <div class="analysis-row">

    <!-- Top 10 words -->
    <div class="card">
      <div class="section-h" style="margin-bottom:8px">Top 10 Words</div>
      <div class="word-list" id="wordList"><div class="empty">No text yet</div></div>
    </div>

    <!-- Char frequency (collapsible) -->
    <div class="card">
      <div class="coll-header" id="charToggle" onclick="toggleChar()">
        <div class="section-h" style="margin-bottom:0">Character Frequency</div>
        <span class="coll-arrow">▼</span>
      </div>
      <div class="coll-body" id="charBody">
        <div class="char-grid" id="charGrid"><div class="empty" style="grid-column:1/-1">No text yet</div></div>
      </div>
    </div>

  </div>

</main>

<script>
(function(){
  const PLATFORMS = [
    {name:'Twitter / X',        limit:280},
    {name:'SMS',                limit:160},
    {name:'Meta Title',         limit:60},
    {name:'Meta Description',   limit:160},
    {name:'YouTube Title',      limit:100},
    {name:'Reddit Title',       limit:300},
    {name:'Instagram Caption',  limit:2200},
    {name:'LinkedIn Post',      limit:3000},
    {name:'YouTube Description',limit:5000},
    {name:'Slack Message',      limit:40000},
  ];

  const STOP = new Set('the a an and or but in on at to for of with by from is are was were be been being have has had do does did will would could should may might shall can that this these those it its i you he she we they me him her us them my your his our their what which who not no so as if up out about into than then there when where how all also just more some one two other new first last after before very too only like well even back still any each much most over such own same make made said get got go come know see take think look want give use find tell ask seem put keep let set turn call try move live play feel help show hear run work bring hold write stand follow'.split(' '));

  // Build platform cards
  const grid = document.getElementById('platformsGrid');
  PLATFORMS.forEach((p, i) => {
    const c = document.createElement('div');
    c.className = 'plat-card';
    c.innerHTML = `<div class="plat-header">
      <span class="plat-name">${p.name}</span>
      <span class="plat-count ok" id="pc${i}">0 / ${p.limit.toLocaleString()}</span>
    </div>
    <div class="progress-track"><div class="progress-fill" id="pf${i}" style="width:0%"></div></div>`;
    grid.appendChild(c);
  });

  // Formatters
  function fmtTime(mins){
    if(mins===0)return'0 sec';
    const s=Math.round(mins*60);
    if(s<60)return s+' sec';
    const m=Math.floor(s/60),r=s%60;
    return r?`${m}m ${r}s`:`${m} min`;
  }
  function fmtBytes(b){
    if(b===0)return'0 B';
    if(b<1024)return b+' B';
    if(b<1048576)return(b/1024).toFixed(1)+' KB';
    return(b/1048576).toFixed(2)+' MB';
  }
  function esc(s){return s.replace(/&/g,'&').replace(/</g,'<').replace(/>/g,'>')}

  function update(){
    const text = document.getElementById('textInput').value;
    const chars = text.length;
    const charsNS = text.replace(/\s/g,'').length;
    const words = text.trim()===''?0:text.trim().split(/\s+/).filter(w=>w).length;
    const sentences = text.trim()===''?0:(text.match(/[^.!?]*[.!?]+/g)||[]).length;
    const paras = text.trim()===''?0:text.split(/\n\s*\n/).filter(p=>p.trim()).length;
    const lines = text===''?0:text.split('\n').length;
    const bytes = new TextEncoder().encode(text).length;

    document.getElementById('sChars').textContent    = chars.toLocaleString();
    document.getElementById('sCharsNS').textContent  = charsNS.toLocaleString();
    document.getElementById('sWords').textContent    = words.toLocaleString();
    document.getElementById('sSentences').textContent= sentences.toLocaleString();
    document.getElementById('sParas').textContent    = paras.toLocaleString();
    document.getElementById('sLines').textContent    = lines.toLocaleString();
    document.getElementById('mRead').textContent     = fmtTime(words/200);
    document.getElementById('mSpeak').textContent    = fmtTime(words/130);
    document.getElementById('mBytes').textContent    = fmtBytes(bytes);

    // Platform bars — colour thresholds: yellow >=80%, red >=100%
    PLATFORMS.forEach((p,i)=>{
      const ratio = chars/p.limit;
      const pct   = Math.min(ratio*100,100);
      const fill  = document.getElementById('pf'+i);
      const cnt   = document.getElementById('pc'+i);
      fill.style.width = pct+'%';
      const cls = ratio>=1?'over':ratio>=0.8?'warn':'';
      fill.className = 'progress-fill'+(cls?' '+cls:'');
      cnt.className  = 'plat-count '+(cls||'ok');
      if(ratio>=1){
        cnt.textContent = '+'+Math.abs(p.limit-chars).toLocaleString()+' over';
      } else {
        cnt.textContent = chars.toLocaleString()+' / '+p.limit.toLocaleString();
      }
    });

    updateWords(text);
    if(document.getElementById('charBody').classList.contains('open')) updateChars(text);
  }

  function updateWords(text){
    const el = document.getElementById('wordList');
    if(!text.trim()){el.innerHTML='<div class="empty">No text yet</div>';return;}
    const raw = text.toLowerCase().match(/[a-z']+/g)||[];
    const freq = {};
    raw.forEach(w=>{
      const c=w.replace(/^'+|'+$/g,'');
      if(c.length>1&&!STOP.has(c)) freq[c]=(freq[c]||0)+1;
    });
    const sorted = Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,10);
    if(!sorted.length){el.innerHTML='<div class="empty">No significant words found</div>';return;}
    const max = sorted[0][1];
    el.innerHTML = sorted.map(([w,n],i)=>`
      <div class="word-row">
        <span class="word-rank">${i+1}</span>
        <div class="word-bar-wrap">
          <div class="word-bar-bg" style="width:${(n/max*100).toFixed(1)}%"></div>
          <span class="word-txt">${esc(w)}</span>
        </div>
        <span class="word-cnt">${n}×</span>
      </div>`).join('');
  }

  function updateChars(text){
    const el = document.getElementById('charGrid');
    if(!text.trim()){el.innerHTML='<div class="empty" style="grid-column:1/-1">No text yet</div>';return;}
    const freq={};
    for(const ch of text){
      if(ch===' '||ch==='\n'||ch==='\t')continue;
      freq[ch]=(freq[ch]||0)+1;
    }
    const sorted=Object.entries(freq).sort((a,b)=>b[1]-a[1]).slice(0,30);
    if(!sorted.length){el.innerHTML='<div class="empty" style="grid-column:1/-1">No printable characters</div>';return;}
    el.innerHTML=sorted.map(([ch,n])=>`
      <div class="char-item">
        <span class="char-ch">${esc(ch)}</span>
        <span class="char-n">${n}×</span>
      </div>`).join('');
  }

  window.toggleChar = function(){
    const h=document.getElementById('charToggle');
    const b=document.getElementById('charBody');
    h.classList.toggle('open');
    b.classList.toggle('open');
    if(b.classList.contains('open')) updateChars(document.getElementById('textInput').value);
  };

  window.copyText = async function(){
    const text=document.getElementById('textInput').value;
    if(!text)return;
    try{
      await navigator.clipboard.writeText(text);
    }catch(e){
      document.getElementById('textInput').select();
      document.execCommand('copy');
    }
    const btn=document.getElementById('copyBtn');
    const orig=btn.textContent;
    btn.textContent='Copied!';
    btn.classList.add('primary');
    setTimeout(()=>{btn.textContent=orig;btn.classList.remove('primary');},1400);
  };

  window.clearText = function(){
    document.getElementById('textInput').value='';
    update();
    document.getElementById('textInput').focus();
  };

  window.update = update;
  update();
})();
</script>
