<body>
<div class="container">
<div class="header">
  <h1>Markdown Preview</h1>
  <p>Write Markdown on the left, see rendered preview on the right.</p>
</div>

<div class="toolbar">
  <button class="tb" onclick="insert('**','**')"><b>B</b></button>
  <button class="tb" onclick="insert('*','*')"><i>I</i></button>
  <button class="tb" onclick="insert('~~','~~')"><s>S</s></button>
  <button class="tb" onclick="insert('`','`')">Code</button>
  <button class="tb" onclick="insert('\n```\n','\n```\n')">Block</button>
  <button class="tb" onclick="insert('[','](url)')">Link</button>
  <button class="tb" onclick="insert('![alt](',')')">Image</button>
  <button class="tb" onclick="insertLine('## ')">H2</button>
  <button class="tb" onclick="insertLine('### ')">H3</button>
  <button class="tb" onclick="insertLine('- ')">List</button>
  <button class="tb" onclick="insertLine('1. ')">OL</button>
  <button class="tb" onclick="insertLine('- [ ] ')">Task</button>
  <button class="tb" onclick="insertLine('> ')">Quote</button>
  <button class="tb" onclick="insertLine('---')">HR</button>
  <button class="tb" onclick="insertTable()">Table</button>
  <button class="tb primary" onclick="copyHTML()">Copy HTML</button>
  <button class="tb" onclick="copyMD()">Copy MD</button>
  <button class="tb" onclick="clearAll()">Clear</button>
</div>

<div class="editor-wrap">
  <div class="editor-pane">
    <div class="pane-header">
      <span>Markdown</span>
      <span class="word-count" id="wordCount">0 words</span>
    </div>
    <textarea id="editor" spellcheck="false" oninput="render()" onscroll="syncScroll()"></textarea>
  </div>
  <div class="preview-pane">
    <div class="pane-header">
      <span>Preview</span>
      <span class="word-count" id="charCount">0 chars</span>
    </div>
